interface CronResult {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<keyof CronResult, [number, number]> = {
  minute: [0, 59],
  hour: [0, 23],
  dayOfMonth: [1, 31],
  month: [1, 12],
  dayOfWeek: [0, 7],
};

function range(start: number, end: number): number[] {
  const result: number[] = [];
  for (let i = start; i <= end; i++) result.push(i);
  return result;
}

function dedupe(values: number[]): number[] {
  return [...new Set(values)].sort((a, b) => a - b);
}

function assertInRange(value: number, min: number, max: number, context: string): void {
  if (value < min || value > max) {
    throw new RangeError(`Value ${value} out of range [${min}, ${max}] for field "${context}"`);
  }
}

function parseSegment(segment: string, min: number, max: number, fieldName: string): number[] {
  // Step: */n or a-b/n
  if (segment.includes("/")) {
    const [rangePart, stepStr] = segment.split("/");
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step < 1) {
      throw new Error(`Invalid step value "${stepStr}" in field "${fieldName}"`);
    }

    let start: number;
    let end: number;

    if (rangePart === "*") {
      start = min;
      end = max;
    } else if (rangePart.includes("-")) {
      const [s, e] = rangePart.split("-").map(Number);
      if (isNaN(s) || isNaN(e)) throw new Error(`Invalid range "${rangePart}" in field "${fieldName}"`);
      assertInRange(s, min, max, fieldName);
      assertInRange(e, min, max, fieldName);
      if (s > e) throw new Error(`Range start ${s} > end ${e} in field "${fieldName}"`);
      start = s;
      end = e;
    } else {
      const val = parseInt(rangePart, 10);
      if (isNaN(val)) throw new Error(`Invalid value "${rangePart}" in field "${fieldName}"`);
      assertInRange(val, min, max, fieldName);
      start = val;
      end = max;
    }

    const result: number[] = [];
    for (let i = start; i <= end; i += step) result.push(i);
    return result;
  }

  // Range: a-b
  if (segment.includes("-")) {
    const [startStr, endStr] = segment.split("-");
    const start = parseInt(startStr, 10);
    const end = parseInt(endStr, 10);
    if (isNaN(start) || isNaN(end)) throw new Error(`Invalid range "${segment}" in field "${fieldName}"`);
    assertInRange(start, min, max, fieldName);
    assertInRange(end, min, max, fieldName);
    if (start > end) throw new Error(`Range start ${start} > end ${end} in field "${fieldName}"`);
    return range(start, end);
  }

  // Wildcard
  if (segment === "*") {
    return range(min, max);
  }

  // Single number
  const value = parseInt(segment, 10);
  if (isNaN(value)) throw new Error(`Invalid value "${segment}" in field "${fieldName}"`);
  assertInRange(value, min, max, fieldName);
  return [value];
}

function parseField(expression: string, min: number, max: number, fieldName: string): number[] {
  const segments = expression.split(",");
  const values: number[] = [];
  for (const segment of segments) {
    const parsed = parseSegment(segment.trim(), min, max, fieldName);
    values.push(...parsed);
  }
  // Normalize dayOfWeek: treat 7 as 0 (Sunday)
  const normalized = fieldName === "dayOfWeek"
    ? values.map((v) => (v === 7 ? 0 : v))
    : values;
  return dedupe(normalized);
}

export default function parseCron(expression: string): CronResult {
  if (typeof expression !== "string") {
    throw new TypeError("Cron expression must be a string");
  }

  const fields = expression.trim().split(/\s+/);
  if (fields.length !== 5) {
    throw new Error(`Expected 5 fields, got ${fields.length}`);
  }

  const [minuteExpr, hourExpr, domExpr, monthExpr, dowExpr] = fields;
  const fieldNames = Object.keys(FIELD_RANGES) as (keyof CronResult)[];

  const [minute, hour, dayOfMonth, month, dayOfWeek] = [
    minuteExpr,
    hourExpr,
    domExpr,
    monthExpr,
    dowExpr,
  ].map((expr, i) => {
    const name = fieldNames[i];
    const [min, max] = FIELD_RANGES[name];
    return parseField(expr, min, max, name);
  });

  return { minute, hour, dayOfMonth, month, dayOfWeek };
}

export interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldMeta {
  min: number;
  max: number;
}

const FIELD_META: Record<keyof CronFields, FieldMeta> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 6  },
};

const FIELD_ORDER: Array<keyof CronFields> = [
  "minute",
  "hour",
  "dayOfMonth",
  "month",
  "dayOfWeek",
];

function rangeArray(from: number, to: number, step = 1): number[] {
  if (step < 1) {
    throw new RangeError(`Step must be >= 1, got ${step}`);
  }
  const result: number[] = [];
  for (let i = from; i <= to; i += step) {
    result.push(i);
  }
  return result;
}

function assertInRange(value: number, meta: FieldMeta, context: string): void {
  if (!Number.isInteger(value) || value < meta.min || value > meta.max) {
    throw new RangeError(
      `Value ${value} out of range [${meta.min}, ${meta.max}] in field "${context}"`
    );
  }
}

function parseInteger(raw: string, meta: FieldMeta, context: string): number {
  const n = Number(raw);
  if (!Number.isFinite(n) || String(Math.floor(n)) !== raw.trim()) {
    throw new TypeError(`Non-integer token "${raw}" in field "${context}"`);
  }
  assertInRange(n, meta, context);
  return n;
}

function parseToken(token: string, meta: FieldMeta, fieldName: string): number[] {
  const trimmed = token.trim();

  if (trimmed === "") {
    throw new SyntaxError(`Empty token in field "${fieldName}"`);
  }

  // Wildcard: "*"
  if (trimmed === "*") {
    return rangeArray(meta.min, meta.max);
  }

  // Step: "*/<step>" or "<start>/<step>"
  if (trimmed.includes("/")) {
    const slashParts = trimmed.split("/");
    if (slashParts.length !== 2) {
      throw new SyntaxError(`Invalid step expression "${trimmed}" in field "${fieldName}"`);
    }
    const [basePart, stepPart] = slashParts;
    const step = Number(stepPart);
    if (!Number.isInteger(step) || step < 1) {
      throw new RangeError(`Invalid step "${stepPart}" in field "${fieldName}"`);
    }

    if (basePart === "*") {
      return rangeArray(meta.min, meta.max, step);
    }

    // Support "<start>/<step>" where base may be a range or single number
    if (basePart.includes("-")) {
      const dashParts = basePart.split("-");
      if (dashParts.length !== 2) {
        throw new SyntaxError(`Invalid range in step expression "${trimmed}" in field "${fieldName}"`);
      }
      const from = parseInteger(dashParts[0], meta, fieldName);
      const to   = parseInteger(dashParts[1], meta, fieldName);
      if (from > to) {
        throw new RangeError(`Range start ${from} > end ${to} in field "${fieldName}"`);
      }
      return rangeArray(from, to, step);
    }

    const start = parseInteger(basePart, meta, fieldName);
    return rangeArray(start, meta.max, step);
  }

  // Range: "<from>-<to>"
  if (trimmed.includes("-")) {
    const dashParts = trimmed.split("-");
    if (dashParts.length !== 2) {
      throw new SyntaxError(`Invalid range "${trimmed}" in field "${fieldName}"`);
    }
    const from = parseInteger(dashParts[0], meta, fieldName);
    const to   = parseInteger(dashParts[1], meta, fieldName);
    if (from > to) {
      throw new RangeError(`Range start ${from} > end ${to} in field "${fieldName}"`);
    }
    return rangeArray(from, to);
  }

  // Single value
  return [parseInteger(trimmed, meta, fieldName)];
}

function parseField(raw: string, meta: FieldMeta, fieldName: string): number[] {
  if (raw === null || raw === undefined) {
    throw new TypeError(`Null or undefined value for field "${fieldName}"`);
  }

  const trimmed = raw.trim();
  if (trimmed === "") {
    throw new SyntaxError(`Empty expression for field "${fieldName}"`);
  }

  const tokens = trimmed.split(",");
  const valueSet = new Set<number>();

  for (const token of tokens) {
    const values = parseToken(token, meta, fieldName);
    for (const v of values) {
      valueSet.add(v);
    }
  }

  return Array.from(valueSet).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronFields {
  if (typeof expression !== "string") {
    throw new TypeError(`Expected a string, got ${typeof expression}`);
  }

  const parts = expression.trim().split(/\s+/);

  if (parts.length !== 5) {
    throw new SyntaxError(
      `Cron expression must have exactly 5 fields, got ${parts.length}: "${expression}"`
    );
  }

  const result = {} as CronFields;

  for (let i = 0; i < FIELD_ORDER.length; i++) {
    const fieldName = FIELD_ORDER[i];
    const meta      = FIELD_META[fieldName];
    result[fieldName] = parseField(parts[i], meta, fieldName);
  }

  return result;
}

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: Primitive | NestedObject | Array<unknown> };
type FlatObject = { [key: string]: Primitive };

function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: FlatObject = {}
): FlatObject {
  if (obj === null || typeof obj !== "object" || Array.isArray(obj)) {
    if (prefix) result[prefix] = obj as Primitive;
    return result;
  }

  const keys = Object.keys(obj);

  if (keys.length === 0) {
    if (prefix) result[prefix] = null;
    return result;
  }

  for (const key of keys) {
    const value = obj[key];
    const newKey = prefix ? `${prefix}.${key}` : key;

    if (
      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value)
    ) {
      flattenObject(value as NestedObject, newKey, result);
    } else {
      result[newKey] = value as Primitive;
    }
  }

  return result;
}

export default flattenObject;

type CronField = "minute" | "hour" | "dayOfMonth" | "month" | "dayOfWeek";

interface CronResult {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<CronField, { min: number; max: number }> = {
  minute: { min: 0, max: 59 },
  hour: { min: 0, max: 23 },
  dayOfMonth: { min: 1, max: 31 },
  month: { min: 1, max: 12 },
  dayOfWeek: { min: 0, max: 7 },
};

const FIELD_ORDER: CronField[] = [
  "minute",
  "hour",
  "dayOfMonth",
  "month",
  "dayOfWeek",
];

function clamp(value: number, min: number, max: number): number {
  if (value < min || value > max) {
    throw new RangeError(`Value ${value} is out of range [${min}, ${max}]`);
  }
  return value;
}

function parseSegment(
  segment: string,
  min: number,
  max: number,
  field: CronField
): number[] {
  const effectiveMax = field === "dayOfWeek" && max === 7 ? 7 : max;

  if (segment === "*") {
    return Array.from(
      { length: effectiveMax - min + 1 },
      (_, i) => i + min
    );
  }

  if (segment.startsWith("*/")) {
    const step = parseInt(segment.slice(2), 10);
    if (isNaN(step) || step <= 0) {
      throw new Error(`Invalid step value in segment: ${segment}`);
    }
    const values: number[] = [];
    for (let i = min; i <= effectiveMax; i += step) {
      values.push(i);
    }
    return values;
  }

  if (segment.includes("-")) {
    const parts = segment.split("-");
    if (parts.length !== 2) {
      throw new Error(`Invalid range expression: ${segment}`);
    }
    const [start, end] = parts.map((p) => parseInt(p, 10));
    if (isNaN(start) || isNaN(end)) {
      throw new Error(`Invalid range values in: ${segment}`);
    }
    clamp(start, min, effectiveMax);
    clamp(end, min, effectiveMax);
    if (start > end) {
      throw new RangeError(
        `Range start ${start} is greater than end ${end} in: ${segment}`
      );
    }
    return Array.from({ length: end - start + 1 }, (_, i) => i + start);
  }

  const value = parseInt(segment, 10);
  if (isNaN(value)) {
    throw new Error(`Invalid cron field value: ${segment}`);
  }
  clamp(value, min, effectiveMax);
  return [value];
}

function parseField(expression: string, field: CronField): number[] {
  const { min, max } = FIELD_RANGES[field];

  const parts = expression.split(",");
  const results = new Set<number>();

  for (const part of parts) {
    const trimmed = part.trim();
    if (trimmed === "") {
      throw new Error(`Empty segment in cron field: ${expression}`);
    }

    if (trimmed.includes("/") && !trimmed.startsWith("*/")) {
      const [rangePart, stepPart] = trimmed.split("/");
      const step = parseInt(stepPart, 10);
      if (isNaN(step) || step <= 0) {
        throw new Error(`Invalid step value in: ${trimmed}`);
      }
      const effectiveMax = field === "dayOfWeek" ? 7 : max;

      let rangeStart: number;
      let rangeEnd: number;

      if (rangePart === "*") {
        rangeStart = min;
        rangeEnd = effectiveMax;
      } else if (rangePart.includes("-")) {
        const [s, e] = rangePart.split("-").map((p) => parseInt(p, 10));
        if (isNaN(s) || isNaN(e)) {
          throw new Error(`Invalid range in step expression: ${trimmed}`);
        }
        clamp(s, min, effectiveMax);
        clamp(e, min, effectiveMax);
        rangeStart = s;
        rangeEnd = e;
      } else {
        const base = parseInt(rangePart, 10);
        if (isNaN(base)) {
          throw new Error(`Invalid base in step expression: ${trimmed}`);
        }
        clamp(base, min, effectiveMax);
        rangeStart = base;
        rangeEnd = effectiveMax;
      }

      for (let i = rangeStart; i <= rangeEnd; i += step) {
        results.add(i);
      }
    } else {
      const values = parseSegment(trimmed, min, max, field);
      for (const v of values) {
        results.add(v);
      }
    }
  }

  const sorted = Array.from(results).sort((a, b) => a - b);

  if (field === "dayOfWeek") {
    return sorted.map((v) => (v === 7 ? 0 : v)).filter(
      (v, i, arr) => arr.indexOf(v) === i
    ).sort((a, b) => a - b);
  }

  return sorted;
}

export default function parseCron(expression: string): CronResult {
  if (typeof expression !== "string") {
    throw new TypeError("Cron expression must be a string");
  }

  const trimmed = expression.trim();
  if (!trimmed) {
    throw new Error("Cron expression cannot be empty");
  }

  const fields = trimmed.split(/\s+/);
  if (fields.length !== 5) {
    throw new Error(
      `Invalid cron expression: expected 5 fields, got ${fields.length}`
    );
  }

  const result = {} as CronResult;

  for (let i = 0; i < FIELD_ORDER.length; i++) {
    const field = FIELD_ORDER[i];
    result[field] = parseField(fields[i], field);
  }

  return result;
}

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: NestedObject | Primitive | unknown[] };
type FlatObject = { [key: string]: Primitive | unknown[] };

function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: FlatObject = {}
): FlatObject {
  if (obj === null || obj === undefined || typeof obj !== "object") {
    if (prefix) result[prefix] = obj as Primitive;
    return result;
  }

  if (Array.isArray(obj)) {
    if (prefix) result[prefix] = obj;
    return result;
  }

  const keys = Object.keys(obj);

  if (keys.length === 0) {
    if (prefix) result[prefix] = {};
    return result;
  }

  for (const key of keys) {
    const newKey = prefix ? `${prefix}.${key}` : key;
    const value = obj[key];

    if (
      value !== null &&
      value !== undefined &&
      typeof value === "object" &&
      !Array.isArray(value)
    ) {
      flattenObject(value as NestedObject, newKey, result);
    } else {
      result[newKey] = value as Primitive | unknown[];
    }
  }

  return result;
}

export default flattenObject;

export interface CronExpression {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldConfig {
  name: keyof CronExpression;
  min: number;
  max: number;
}

const FIELD_CONFIGS: FieldConfig[] = [
  { name: "minute",     min: 0,  max: 59 },
  { name: "hour",       min: 0,  max: 23 },
  { name: "dayOfMonth", min: 1,  max: 31 },
  { name: "month",      min: 1,  max: 12 },
  { name: "dayOfWeek",  min: 0,  max: 6  },
];

function isNonNegativeInteger(s: string): boolean {
  return /^\d+$/.test(s);
}

function assertInRange(value: number, min: number, max: number, context: string): void {
  if (value < min || value > max) {
    throw new RangeError(
      `Value ${value} out of valid range [${min}–${max}] in ${context}`
    );
  }
}

function parseToken(
  token: string,
  min: number,
  max: number,
  fieldName: string
): number[] {
  const t = token.trim();

  if (t === "") {
    throw new Error(`Empty token encountered in field "${fieldName}"`);
  }

  // Step expression: */N  |  N/N  |  N-M/N
  if (t.includes("/")) {
    const slashIndex = t.indexOf("/");
    const slashCount = t.split("/").length - 1;

    if (slashCount !== 1) {
      throw new Error(
        `Invalid step expression "${t}" in field "${fieldName}": exactly one "/" allowed`
      );
    }

    const rangeStr = t.slice(0, slashIndex);
    const stepStr  = t.slice(slashIndex + 1);

    if (!isNonNegativeInteger(stepStr)) {
      throw new Error(
        `Invalid step "${stepStr}" in field "${fieldName}": must be a non-negative integer`
      );
    }

    const step = parseInt(stepStr, 10);

    if (step === 0) {
      throw new Error(`Step value cannot be 0 in field "${fieldName}"`);
    }

    let start: number;
    let end: number;

    if (rangeStr === "*") {
      start = min;
      end   = max;
    } else if (rangeStr.includes("-")) {
      const [startStr, endStr, ...extra] = rangeStr.split("-");

      if (extra.length > 0 || !isNonNegativeInteger(startStr) || !isNonNegativeInteger(endStr)) {
        throw new Error(
          `Invalid range "${rangeStr}" in step expression for field "${fieldName}"`
        );
      }

      start = parseInt(startStr, 10);
      end   = parseInt(endStr,   10);
    } else {
      if (!isNonNegativeInteger(rangeStr)) {
        throw new Error(
          `Invalid start value "${rangeStr}" in step expression for field "${fieldName}"`
        );
      }
      start = parseInt(rangeStr, 10);
      end   = max;
    }

    assertInRange(start, min, max, `field "${fieldName}" step start`);
    assertInRange(end,   min, max, `field "${fieldName}" step end`);

    if (start > end) {
      throw new Error(
        `Step range start ${start} > end ${end} in field "${fieldName}"`
      );
    }

    const values: number[] = [];
    for (let i = start; i <= end; i += step) {
      values.push(i);
    }
    return values;
  }

  // Wildcard
  if (t === "*") {
    return Array.from({ length: max - min + 1 }, (_, i) => min + i);
  }

  // Range: N-M
  if (t.includes("-")) {
    const parts = t.split("-");

    if (parts.length !== 2) {
      throw new Error(
        `Invalid range "${t}" in field "${fieldName}": expected exactly one "-"`
      );
    }

    const [startStr, endStr] = parts;

    if (!isNonNegativeInteger(startStr) || !isNonNegativeInteger(endStr)) {
      throw new Error(
        `Invalid range values "${t}" in field "${fieldName}": both bounds must be non-negative integers`
      );
    }

    const start = parseInt(startStr, 10);
    const end   = parseInt(endStr,   10);

    assertInRange(start, min, max, `field "${fieldName}" range start`);
    assertInRange(end,   min, max, `field "${fieldName}" range end`);

    if (start > end) {
      throw new Error(
        `Range start ${start} > end ${end} in field "${fieldName}"`
      );
    }

    return Array.from({ length: end - start + 1 }, (_, i) => start + i);
  }

  // Single numeric value
  if (!isNonNegativeInteger(t)) {
    throw new Error(
      `Invalid value "${t}" in field "${fieldName}": expected a number, "*", a range, a step, or a list`
    );
  }

  const value = parseInt(t, 10);
  assertInRange(value, min, max, `field "${fieldName}"`);

  return [value];
}

function parseField(
  field: string,
  min: number,
  max: number,
  fieldName: string
): number[] {
  const trimmed = field.trim();

  if (trimmed === "") {
    throw new Error(`Field "${fieldName}" is empty`);
  }

  // Comma-separated list — wildcards are semantically invalid within a list
  if (trimmed.includes(",")) {
    const parts = trimmed.split(",");
    const valueSet = new Set<number>();

    for (const part of parts) {
      const partTrimmed = part.trim();

      if (partTrimmed === "") {
        throw new Error(
          `Empty element in comma-separated list for field "${fieldName}": trailing/leading/consecutive commas are not allowed`
        );
      }

      if (partTrimmed === "*") {
        throw new Error(
          `Wildcard "*" cannot appear inside a comma-separated list for field "${fieldName}": use "*" alone instead`
        );
      }

      const parsed = parseToken(partTrimmed, min, max, fieldName);
      parsed.forEach((v) => valueSet.add(v));
    }

    return Array.from(valueSet).sort((a, b) => a - b);
  }

  return parseToken(trimmed, min, max, fieldName);
}

export default function parseCron(expression: string): CronExpression {
  if (expression === null || expression === undefined) {
    throw new TypeError("Cron expression must not be null or undefined");
  }

  if (typeof expression !== "string") {
    throw new TypeError(
      `Cron expression must be a string, received ${typeof expression}`
    );
  }

  const trimmed = expression.trim();

  if (trimmed === "") {
    throw new Error("Cron expression must not be empty");
  }

  const fields = trimmed.split(/\s+/);

  if (fields.length !== 5) {
    throw new Error(
      `Cron expression must contain exactly 5 whitespace-separated fields, got ${fields.length}: "${expression}"`
    );
  }

  const result = {} as CronExpression;

  for (let i = 0; i < FIELD_CONFIGS.length; i++) {
    const { name, min, max } = FIELD_CONFIGS[i];
    result[name] = parseField(fields[i], min, max, name);
  }

  return result;
}

type Primitive = string | number | boolean | bigint | null | undefined;
type NestedObject = { [key: string]: NestedObject | Primitive | unknown[] };
type FlattenedObject = Record<string, Primitive>;

function isPlainObject(value: unknown): value is NestedObject {
  if (value === null || typeof value !== "object") return false;
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function flattenRecursive(
  input: object,
  prefix: string,
  result: FlattenedObject,
  ancestors: WeakSet<object>,
): void {
  if (ancestors.has(input)) {
    throw new Error(
      `Circular reference detected at path: "${prefix || "<root>"}"`,
    );
  }

  const keys = Object.keys(input);

  // Preserve empty objects/arrays as-is — no leaf key to produce,
  // but warn-free: caller asked to flatten something with no children.
  if (keys.length === 0) return;

  ancestors.add(input);

  try {
    for (const key of keys) {
      // Guard: skip inherited props (Object.keys won't surface them,
      // but be explicit about intent).
      if (!Object.prototype.hasOwnProperty.call(input, key)) continue;

      const value = (input as Record<string, unknown>)[key];
      const fullKey = prefix.length > 0 ? `${prefix}.${key}` : key;

      if (Array.isArray(value)) {
        // Recurse into arrays using numeric index keys (e.g. "a.0.b")
        flattenRecursive(value, fullKey, result, ancestors);
      } else if (isPlainObject(value)) {
        // Recurse into plain objects only — Date, Map, Set, RegExp, etc.
        // are intentionally treated as leaf values below.
        flattenRecursive(value, fullKey, result, ancestors);
      } else {
        // Leaf: primitives plus non-plain objects (Date, RegExp, …)
        result[fullKey] = value as Primitive;
      }
    }
  } finally {
    // Remove after visiting so the same object reference can legally
    // appear at multiple non-circular paths in the tree.
    ancestors.delete(input);
  }
}

export default function flattenObject(input: NestedObject): FlattenedObject {
  if (input === null || input === undefined) {
    throw new TypeError(
      `flattenObject: expected a plain object, received ${input}`,
    );
  }
  if (!isPlainObject(input)) {
    throw new TypeError(
      `flattenObject: expected a plain object, received ${
        Array.isArray(input) ? "Array" : typeof input
      }`,
    );
  }

  const result: FlattenedObject = {};
  flattenRecursive(input, "", result, new WeakSet());
  return result;
}

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: Primitive | NestedObject | Array<unknown> };
type FlatObject = { [key: string]: Primitive | Array<unknown> };

function flattenObject(
  input: NestedObject,
  prefix: string = "",
  visited: WeakSet<object> = new WeakSet()
): FlatObject {
  if (input === null || typeof input !== "object") {
    return prefix ? { [prefix]: input as Primitive } : {};
  }

  if (visited.has(input)) {
    return prefix ? { [prefix]: "[Circular]" } : {};
  }

  visited.add(input);

  const result: FlatObject = {};

  const keys = Object.keys(input);

  if (keys.length === 0) {
    if (prefix) {
      result[prefix] = {};
    }
    visited.delete(input);
    return result;
  }

  for (const key of keys) {
    if (!Object.prototype.hasOwnProperty.call(input, key)) {
      continue;
    }

    const value = input[key];
    const newKey = prefix ? `${prefix}.${key}` : key;

    if (
      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value)
    ) {
      const nested = flattenObject(value as NestedObject, newKey, visited);
      Object.assign(result, nested);
    } else {
      result[newKey] = value as Primitive | Array<unknown>;
    }
  }

  visited.delete(input);

  return result;
}

export default flattenObject;

interface CronResult {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

type FieldName = keyof CronResult;

const FIELD_RANGES: Record<FieldName, { min: number; max: number }> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 7  },
};

const FIELD_ORDER: FieldName[] = [
  "minute",
  "hour",
  "dayOfMonth",
  "month",
  "dayOfWeek",
];

function assertInRange(value: number, min: number, max: number, field: string): void {
  if (value < min || value > max) {
    throw new RangeError(
      `Value ${value} out of range [${min}, ${max}] for field "${field}"`
    );
  }
}

function parseSegment(segment: string, min: number, max: number, field: string): number[] {
  // Step: */n or x/n
  if (segment.includes("/")) {
    const [rangePart, stepStr] = segment.split("/");
    const step = parseInt(stepStr, 10);

    if (isNaN(step) || step < 1) {
      throw new SyntaxError(`Invalid step value "${stepStr}" in field "${field}"`);
    }

    let start = min;
    let end = max;

    if (rangePart !== "*") {
      if (rangePart.includes("-")) {
        const [startStr, endStr] = rangePart.split("-");
        start = parseInt(startStr, 10);
        end   = parseInt(endStr,   10);
        if (isNaN(start) || isNaN(end)) {
          throw new SyntaxError(`Invalid range "${rangePart}" in field "${field}"`);
        }
        assertInRange(start, min, max, field);
        assertInRange(end,   min, max, field);
        if (start > end) {
          throw new RangeError(`Range start ${start} > end ${end} in field "${field}"`);
        }
      } else {
        start = parseInt(rangePart, 10);
        if (isNaN(start)) {
          throw new SyntaxError(`Invalid step expression "${segment}" in field "${field}"`);
        }
        assertInRange(start, min, max, field);
        end = max;
      }
    }

    const values: number[] = [];
    for (let v = start; v <= end; v += step) {
      values.push(v);
    }
    return values;
  }

  // Range: x-y
  if (segment.includes("-")) {
    const [startStr, endStr] = segment.split("-");
    const start = parseInt(startStr, 10);
    const end   = parseInt(endStr,   10);

    if (isNaN(start) || isNaN(end)) {
      throw new SyntaxError(`Invalid range "${segment}" in field "${field}"`);
    }
    assertInRange(start, min, max, field);
    assertInRange(end,   min, max, field);
    if (start > end) {
      throw new RangeError(`Range start ${start} > end ${end} in field "${field}"`);
    }

    const values: number[] = [];
    for (let v = start; v <= end; v++) {
      values.push(v);
    }
    return values;
  }

  // Wildcard
  if (segment === "*") {
    const values: number[] = [];
    for (let v = min; v <= max; v++) {
      values.push(v);
    }
    return values;
  }

  // Number
  const value = parseInt(segment, 10);
  if (isNaN(value)) {
    throw new SyntaxError(`Invalid value "${segment}" in field "${field}"`);
  }
  assertInRange(value, min, max, field);
  return [value];
}

function parseField(expression: string, field: FieldName): number[] {
  const { min, max } = FIELD_RANGES[field];

  // Comma-separated list
  const parts = expression.split(",");
  const collected = new Set<number>();

  for (const part of parts) {
    const trimmed = part.trim();
    if (trimmed === "") {
      throw new SyntaxError(`Empty segment in field "${field}"`);
    }
    for (const v of parseSegment(trimmed, min, max, field)) {
      // Normalize dayOfWeek: treat 7 as 0 (both mean Sunday)
      const normalized = field === "dayOfWeek" && v === 7 ? 0 : v;
      collected.add(normalized);
    }
  }

  return [...collected].sort((a, b) => a - b);
}

function parseCron(expression: string): CronResult {
  if (typeof expression !== "string") {
    throw new TypeError("Cron expression must be a string");
  }

  const fields = expression.trim().split(/\s+/);

  if (fields.length !== 5) {
    throw new SyntaxError(
      `Expected 5 fields, got ${fields.length}: "${expression}"`
    );
  }

  const result = {} as CronResult;

  for (let i = 0; i < FIELD_ORDER.length; i++) {
    const fieldName = FIELD_ORDER[i];
    result[fieldName] = parseField(fields[i], fieldName);
  }

  return result;
}

export default parseCron;

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: Primitive | NestedObject | Array<unknown> };
type FlatObject = { [key: string]: Primitive };

function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: FlatObject = {}
): FlatObject {
  if (obj === null || obj === undefined || typeof obj !== "object") {
    if (prefix) result[prefix] = obj as Primitive;
    return result;
  }

  if (Array.isArray(obj)) {
    if (obj.length === 0) {
      if (prefix) result[prefix] = null;
    } else {
      obj.forEach((item, index) => {
        const key = prefix ? `${prefix}.${index}` : `${index}`;
        flattenObject(item as NestedObject, key, result);
      });
    }
    return result;
  }

  const keys = Object.keys(obj);

  if (keys.length === 0) {
    if (prefix) result[prefix] = null;
    return result;
  }

  for (const key of keys) {
    const value = obj[key];
    const newKey = prefix ? `${prefix}.${key}` : key;

    if (
      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value)
    ) {
      flattenObject(value as NestedObject, newKey, result);
    } else if (Array.isArray(value)) {
      flattenObject(value as unknown as NestedObject, newKey, result);
    } else {
      result[newKey] = value as Primitive;
    }
  }

  return result;
}

export default flattenObject;

type PlainObject = Record<string, unknown>;

function isPlainObject(value: unknown): value is PlainObject {
  if (value === null || typeof value !== "object") return false;
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function flattenObjectInner(
  obj: PlainObject,
  prefix: string,
  seen: WeakSet<object>,
  result: PlainObject,
): void {
  if (seen.has(obj)) {
    throw new Error(
      `Circular reference detected${prefix ? ` at key "${prefix}"` : ""}`,
    );
  }

  seen.add(obj);

  for (const key of Object.keys(obj)) {
    const value = obj[key];
    const flatKey = prefix ? `${prefix}.${key}` : key;

    if (isPlainObject(value) && Object.keys(value).length > 0) {
      // Non-empty plain object: recurse deeper
      flattenObjectInner(value, flatKey, seen, result);
    } else {
      // Leaf: primitives, null, arrays, class instances, Dates, RegExps,
      // symbols, bigints, undefined, and empty plain objects all land here
      result[flatKey] = value;
    }
  }

  // Remove after visiting so the same object reference can appear in
  // sibling branches without being mistaken for a cycle
  seen.delete(obj);
}

function flattenObject(obj: PlainObject): PlainObject {
  if (!isPlainObject(obj)) {
    throw new TypeError(
      `flattenObject expects a plain object, received: ${
        obj === null ? "null" : typeof obj
      }`,
    );
  }

  const result: PlainObject = {};
  flattenObjectInner(obj, "", new WeakSet(), result);
  return result;
}

export default flattenObject;

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: Primitive | NestedObject | Array<unknown> };
type FlatObject = { [key: string]: Primitive };

function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: FlatObject = {}
): FlatObject {
  if (obj === null || obj === undefined || typeof obj !== "object") {
    if (prefix) result[prefix] = obj as Primitive;
    return result;
  }

  if (Array.isArray(obj)) {
    if (obj.length === 0) {
      if (prefix) result[prefix] = null;
    } else {
      obj.forEach((item, index) => {
        const key = prefix ? `${prefix}.${index}` : `${index}`;
        flattenObject(item as NestedObject, key, result);
      });
    }
    return result;
  }

  const keys = Object.keys(obj);

  if (keys.length === 0) {
    if (prefix) result[prefix] = null;
    return result;
  }

  for (const key of keys) {
    const value = obj[key];
    const newKey = prefix ? `${prefix}.${key}` : key;

    if (
      value !== null &&
      value !== undefined &&
      typeof value === "object" &&
      !Array.isArray(value)
    ) {
      flattenObject(value as NestedObject, newKey, result);
    } else if (Array.isArray(value)) {
      flattenObject(value as unknown as NestedObject, newKey, result);
    } else {
      result[newKey] = value as Primitive;
    }
  }

  return result;
}

export default flattenObject;

type CronResult = {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
};

const FIELD_RANGES: Record<keyof CronResult, [number, number]> = {
  minute: [0, 59],
  hour: [0, 23],
  dayOfMonth: [1, 31],
  month: [1, 12],
  dayOfWeek: [0, 6],
};

function parseField(expr: string, min: number, max: number): number[] {
  const results = new Set<number>();

  for (const part of expr.split(",")) {
    if (part === "*") {
      for (let i = min; i <= max; i++) results.add(i);
      continue;
    }

    const stepMatch = part.match(/^(\*|(\d+)-(\d+))\/(\d+)$/);
    if (stepMatch) {
      const step = parseInt(stepMatch[4], 10);
      if (step <= 0) throw new Error(`Invalid step value: ${step}`);
      const rangeMin = stepMatch[1] === "*" ? min : parseInt(stepMatch[2], 10);
      const rangeMax = stepMatch[1] === "*" ? max : parseInt(stepMatch[3], 10);
      validateRange(rangeMin, rangeMax, min, max);
      for (let i = rangeMin; i <= rangeMax; i += step) results.add(i);
      continue;
    }

    const rangeMatch = part.match(/^(\d+)-(\d+)$/);
    if (rangeMatch) {
      const lo = parseInt(rangeMatch[1], 10);
      const hi = parseInt(rangeMatch[2], 10);
      validateRange(lo, hi, min, max);
      for (let i = lo; i <= hi; i++) results.add(i);
      continue;
    }

    if (/^\d+$/.test(part)) {
      const val = parseInt(part, 10);
      if (val < min || val > max) {
        throw new Error(`Value ${val} out of range [${min}, ${max}]`);
      }
      results.add(val);
      continue;
    }

    throw new Error(`Invalid cron field expression: "${part}"`);
  }

  return Array.from(results).sort((a, b) => a - b);
}

function validateRange(lo: number, hi: number, min: number, max: number): void {
  if (lo > hi) throw new Error(`Invalid range: ${lo}-${hi}`);
  if (lo < min || hi > max) {
    throw new Error(`Range ${lo}-${hi} out of bounds [${min}, ${max}]`);
  }
}

export default function parseCron(expression: string): CronResult {
  if (typeof expression !== "string") {
    throw new Error("Cron expression must be a string");
  }

  const fields = expression.trim().split(/\s+/);
  if (fields.length !== 5) {
    throw new Error(
      `Expected 5 fields, got ${fields.length}: "${expression}"`
    );
  }

  const keys = Object.keys(FIELD_RANGES) as (keyof CronResult)[];
  const result = {} as CronResult;

  for (let i = 0; i < keys.length; i++) {
    const key = keys[i];
    const [min, max] = FIELD_RANGES[key];
    result[key] = parseField(fields[i], min, max);
  }

  return result;
}

type Primitive = string | number | boolean | null | undefined | symbol | bigint;
type FlatValue = Primitive | unknown[] | Date | RegExp | Function;
type NestedObject = { [key: string]: unknown };
type FlatObject = { [key: string]: FlatValue };

const isPlainObject = (value: unknown): value is NestedObject =>
  value !== null &&
  typeof value === "object" &&
  !Array.isArray(value) &&
  !(value instanceof Date) &&
  !(value instanceof RegExp) &&
  !(value instanceof Function) &&
  Object.getPrototypeOf(value) === Object.prototype;

const flattenObject = (
  input: unknown,
  options: { delimiter?: string; maxDepth?: number } = {}
): FlatObject => {
  const { delimiter = ".", maxDepth = 100 } = options;

  if (!isPlainObject(input)) {
    throw new TypeError(
      `flattenObject: expected a plain object, got ${input === null ? "null" : typeof input}`
    );
  }

  const result: FlatObject = {};
  const seen = new WeakSet<object>();

  const recurse = (current: unknown, prefix: string, depth: number): void => {
    if (depth > maxDepth) {
      throw new RangeError(
        `flattenObject: exceeded maximum depth of ${maxDepth}. Possible circular structure or deeply nested object.`
      );
    }

    if (isPlainObject(current)) {
      if (seen.has(current)) {
        throw new TypeError(
          `flattenObject: circular reference detected at key "${prefix}"`
        );
      }

      seen.add(current);

      const keys = Object.keys(current);

      if (keys.length === 0) {
        // Preserve empty objects as leaf values rather than silently dropping them
        if (prefix !== "") {
          (result as Record<string, unknown>)[prefix] = {};
        }
      } else {
        for (const key of keys) {
          const newKey = prefix === "" ? key : `${prefix}${delimiter}${key}`;
          recurse(current[key], newKey, depth + 1);
        }
      }

      seen.delete(current);
    } else {
      if (prefix === "") {
        // Top-level non-object after initial type check — shouldn't happen
        return;
      }
      result[prefix] = current as FlatValue;
    }
  };

  recurse(input, "", 0);

  return result;
};

export default flattenObject;

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: Primitive | NestedObject | Array<unknown> };
type FlatObject = { [key: string]: Primitive };

function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: FlatObject = {}
): FlatObject {
  if (obj === null || obj === undefined || typeof obj !== "object") {
    if (prefix) result[prefix] = obj as Primitive;
    return result;
  }

  if (Array.isArray(obj)) {
    if (prefix) result[prefix] = JSON.stringify(obj);
    return result;
  }

  const keys = Object.keys(obj);

  if (keys.length === 0) {
    if (prefix) result[prefix] = "{}";
    return result;
  }

  for (const key of keys) {
    const value = obj[key];
    const newKey = prefix ? `${prefix}.${key}` : key;

    if (
      value !== null &&
      value !== undefined &&
      typeof value === "object" &&
      !Array.isArray(value)
    ) {
      flattenObject(value as NestedObject, newKey, result);
    } else {
      result[newKey] = Array.isArray(value)
        ? JSON.stringify(value)
        : (value as Primitive);
    }
  }

  return result;
}

export default flattenObject;

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: NestedObject | Primitive | unknown[] };
type FlatObject = { [key: string]: Primitive | unknown[] };

function flattenObject(
  input: unknown,
  prefix: string = "",
  result: FlatObject = {},
  visited: WeakSet<object> = new WeakSet()
): FlatObject {
  if (input === null || input === undefined) {
    if (prefix !== "") {
      result[prefix] = input as Primitive;
    }
    return result;
  }

  if (typeof input !== "object") {
    if (prefix !== "") {
      result[prefix] = input as Primitive;
    }
    return result;
  }

  if (Array.isArray(input)) {
    if (prefix !== "") {
      result[prefix] = input;
    }
    return result;
  }

  if (visited.has(input as object)) {
    if (prefix !== "") {
      result[prefix] = "[Circular]";
    }
    return result;
  }

  visited.add(input as object);

  const obj = input as NestedObject;
  const keys = Object.keys(obj);

  if (keys.length === 0) {
    if (prefix !== "") {
      result[prefix] = {} as unknown as Primitive;
    }
    return result;
  }

  for (const key of keys) {
    if (!Object.prototype.hasOwnProperty.call(obj, key)) {
      continue;
    }

    const sanitizedKey = String(key);
    const nextPrefix = prefix === "" ? sanitizedKey : `${prefix}.${sanitizedKey}`;
    const value = obj[key];

    if (
      value !== null &&
      value !== undefined &&
      typeof value === "object" &&
      !Array.isArray(value)
    ) {
      flattenObject(value, nextPrefix, result, visited);
    } else {
      result[nextPrefix] = value as Primitive | unknown[];
    }
  }

  return result;
}

export default flattenObject;

type Primitive = string | number | boolean | null | undefined | bigint | symbol;
type NestedObject = { [key: string]: NestedObject | Primitive | unknown[] };
type FlatObject = { [key: string]: Primitive | unknown[] };

function flattenObject(
  input: unknown,
  prefix: string = "",
  visited: WeakSet<object> = new WeakSet()
): FlatObject {
  if (input === null || input === undefined) {
    return prefix ? { [prefix]: input as Primitive } : {};
  }

  if (typeof input !== "object" || Array.isArray(input)) {
    return prefix ? { [prefix]: input as Primitive | unknown[] } : {};
  }

  const obj = input as NestedObject;

  if (visited.has(obj)) {
    return prefix ? { [prefix]: "[Circular]" } : {};
  }

  visited.add(obj);

  const keys = Object.keys(obj);

  if (keys.length === 0) {
    return prefix ? { [prefix]: {} as unknown as Primitive } : {};
  }

  const result: FlatObject = {};

  for (const key of keys) {
    if (!Object.prototype.hasOwnProperty.call(obj, key)) {
      continue;
    }

    const value = obj[key];
    const newKey = prefix.length > 0 ? `${prefix}.${key}` : key;

    if (
      value !== null &&
      value !== undefined &&
      typeof value === "object" &&
      !Array.isArray(value)
    ) {
      const nested = flattenObject(value, newKey, visited);
      const nestedKeys = Object.keys(nested);

      if (nestedKeys.length === 0) {
        result[newKey] = value as unknown as Primitive;
      } else {
        for (const nestedKey of nestedKeys) {
          result[nestedKey] = nested[nestedKey];
        }
      }
    } else {
      result[newKey] = value as Primitive | unknown[];
    }
  }

  visited.delete(obj);

  return result;
}

export default flattenObject;

type CronField = "minute" | "hour" | "dayOfMonth" | "month" | "dayOfWeek";

interface CronExpression {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldBounds {
  readonly min: number;
  readonly max: number;
}

const FIELD_BOUNDS: Readonly<Record<CronField, FieldBounds>> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 6  },
} as const;

const FIELD_ORDER: readonly CronField[] = [
  "minute",
  "hour",
  "dayOfMonth",
  "month",
  "dayOfWeek",
] as const;

function isNonNegativeInteger(s: string): boolean {
  return /^\d+$/.test(s);
}

function assertInBounds(value: number, field: CronField, context: string): void {
  const { min, max } = FIELD_BOUNDS[field];
  if (value < min || value > max) {
    throw new RangeError(
      `Value ${value} is out of valid range [${min}–${max}] for field "${field}" in "${context}"`
    );
  }
}

function expandValues(start: number, end: number, step: number, field: CronField, raw: string): number[] {
  if (step <= 0) {
    throw new RangeError(
      `Step must be >= 1, got ${step} for field "${field}" in "${raw}"`
    );
  }
  if (start > end) {
    throw new RangeError(
      `Range start (${start}) cannot exceed end (${end}) for field "${field}" in "${raw}"`
    );
  }
  assertInBounds(start, field, raw);
  assertInBounds(end, field, raw);

  const values: number[] = [];
  for (let v = start; v <= end; v += step) {
    values.push(v);
  }
  return values;
}

function parseSegment(segment: string, field: CronField): number[] {
  const { min, max } = FIELD_BOUNDS[field];

  if (segment.trim() === "") {
    throw new SyntaxError(`Empty segment encountered in field "${field}"`);
  }

  // --- step expression: base/step ---
  if (segment.includes("/")) {
    const parts = segment.split("/");
    if (parts.length !== 2) {
      throw new SyntaxError(`Invalid step expression "${segment}" for field "${field}"`);
    }
    const [baseStr, stepStr] = parts;

    if (!isNonNegativeInteger(stepStr) || stepStr === "") {
      throw new SyntaxError(
        `Invalid step value "${stepStr}" in "${segment}" for field "${field}"`
      );
    }
    const step = parseInt(stepStr, 10);
    if (step === 0) {
      throw new RangeError(`Step value cannot be 0 in "${segment}" for field "${field}"`);
    }

    // */step
    if (baseStr === "*") {
      return expandValues(min, max, step, field, segment);
    }

    // start-end/step
    if (baseStr.includes("-")) {
      const rangeParts = baseStr.split("-");
      if (rangeParts.length !== 2 || !isNonNegativeInteger(rangeParts[0]) || !isNonNegativeInteger(rangeParts[1])) {
        throw new SyntaxError(
          `Invalid range base "${baseStr}" in "${segment}" for field "${field}"`
        );
      }
      const start = parseInt(rangeParts[0], 10);
      const end   = parseInt(rangeParts[1], 10);
      return expandValues(start, end, step, field, segment);
    }

    // number/step → treat as number–max/step
    if (!isNonNegativeInteger(baseStr)) {
      throw new SyntaxError(
        `Invalid base "${baseStr}" in step expression "${segment}" for field "${field}"`
      );
    }
    const start = parseInt(baseStr, 10);
    assertInBounds(start, field, segment);
    return expandValues(start, max, step, field, segment);
  }

  // --- wildcard ---
  if (segment === "*") {
    return expandValues(min, max, 1, field, segment);
  }

  // --- range: start-end ---
  if (segment.includes("-")) {
    const dashIdx = segment.indexOf("-");
    const startStr = segment.slice(0, dashIdx);
    const endStr   = segment.slice(dashIdx + 1);

    if (!isNonNegativeInteger(startStr) || startStr === "") {
      throw new SyntaxError(
        `Invalid range start "${startStr}" in "${segment}" for field "${field}"`
      );
    }
    if (!isNonNegativeInteger(endStr) || endStr === "" || endStr.includes("-")) {
      throw new SyntaxError(
        `Invalid range end "${endStr}" in "${segment}" for field "${field}"`
      );
    }

    const start = parseInt(startStr, 10);
    const end   = parseInt(endStr, 10);
    return expandValues(start, end, 1, field, segment);
  }

  // --- single numeric value ---
  if (!isNonNegativeInteger(segment)) {
    throw new SyntaxError(`Unrecognised value "${segment}" for field "${field}"`);
  }
  const value = parseInt(segment, 10);
  assertInBounds(value, field, segment);
  return [value];
}

function parseField(rawField: string, field: CronField): number[] {
  const trimmed = rawField.trim();
  if (trimmed === "") {
    throw new SyntaxError(`Field "${field}" is empty`);
  }

  const segments = trimmed.split(",");
  const seen = new Set<number>();

  for (const segment of segments) {
    if (segment === "") {
      throw new SyntaxError(
        `Trailing or consecutive comma in field "${field}": "${rawField}"`
      );
    }
    for (const v of parseSegment(segment, field)) {
      seen.add(v);
    }
  }

  if (seen.size === 0) {
    throw new RangeError(`Field "${field}" resolved to an empty value set`);
  }

  return Array.from(seen).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronExpression {
  if (typeof expression !== "string") {
    throw new TypeError(`parseCron expects a string, received ${typeof expression}`);
  }

  const trimmed = expression.trim();
  if (trimmed === "") {
    throw new SyntaxError("Cron expression must not be empty");
  }

  const rawFields = trimmed.split(/\s+/);

  if (rawFields.length !== 5) {
    throw new SyntaxError(
      `Cron expression must have exactly 5 fields, got ${rawFields.length}: "${expression}"`
    );
  }

  const result = {} as CronExpression;

  for (let i = 0; i < FIELD_ORDER.length; i++) {
    const fieldName = FIELD_ORDER[i];
    // Fail fast on each field before proceeding to the next — avoids partial result
    result[fieldName] = parseField(rawFields[i], fieldName);
  }

  return result;
}

export type CronExpression = {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
};

type FieldConfig = {
  readonly name: string;
  readonly min: number;
  readonly max: number;
};

const FIELD_CONFIGS = [
  { name: "minute",     min: 0,  max: 59 },
  { name: "hour",       min: 0,  max: 23 },
  { name: "dayOfMonth", min: 1,  max: 31 },
  { name: "month",      min: 1,  max: 12 },
  { name: "dayOfWeek",  min: 0,  max: 6  },
] as const satisfies readonly FieldConfig[];

function strictParseInt(raw: string, context: string): number {
  const trimmed = raw.trim();
  if (!/^\d+$/.test(trimmed)) {
    throw new Error(`Expected a non-negative integer in ${context}, got: "${raw}"`);
  }
  return parseInt(trimmed, 10);
}

function assertInRange(value: number, min: number, max: number, context: string): void {
  if (value < min || value > max) {
    throw new RangeError(
      `Value ${value} is outside the valid range [${min}, ${max}] in ${context}`
    );
  }
}

function expandStep(start: number, end: number, step: number): number[] {
  if (step <= 0) throw new Error(`Step must be a positive integer, got: ${step}`);
  const values: number[] = [];
  for (let i = start; i <= end; i += step) {
    values.push(i);
  }
  return values;
}

function parseSegment(segment: string, config: FieldConfig): number[] {
  const { name, min, max } = config;

  // ── Step: */N  |  S-E/N  |  S/N ──────────────────────────────────────────
  if (segment.includes("/")) {
    const parts = segment.split("/");
    if (parts.length !== 2 || parts[0] === "" || parts[1] === "") {
      throw new Error(`Malformed step expression in field "${name}": "${segment}"`);
    }
    const [rangePart, stepStr] = parts;
    const step = strictParseInt(stepStr, `step of field "${name}"`);
    if (step === 0) {
      throw new Error(`Step value cannot be zero in field "${name}"`);
    }

    let rangeStart: number;
    let rangeEnd: number;

    if (rangePart === "*") {
      rangeStart = min;
      rangeEnd = max;
    } else if (rangePart.includes("-")) {
      const dashParts = rangePart.split("-");
      if (dashParts.length !== 2) {
        throw new Error(`Malformed range in step expression for field "${name}": "${rangePart}"`);
      }
      rangeStart = strictParseInt(dashParts[0], `range start of field "${name}"`);
      rangeEnd   = strictParseInt(dashParts[1], `range end of field "${name}"`);
    } else {
      rangeStart = strictParseInt(rangePart, `range start of field "${name}"`);
      rangeEnd   = max;
    }

    assertInRange(rangeStart, min, max, `range start of field "${name}"`);
    assertInRange(rangeEnd,   min, max, `range end of field "${name}"`);

    if (rangeStart > rangeEnd) {
      throw new Error(
        `Range start ${rangeStart} exceeds end ${rangeEnd} in field "${name}"`
      );
    }

    return expandStep(rangeStart, rangeEnd, step);
  }

  // ── Wildcard ──────────────────────────────────────────────────────────────
  if (segment === "*") {
    return expandStep(min, max, 1);
  }

  // ── Range: S-E ────────────────────────────────────────────────────────────
  if (segment.includes("-")) {
    const dashParts = segment.split("-");
    if (dashParts.length !== 2) {
      throw new Error(`Malformed range in field "${name}": "${segment}"`);
    }
    const start = strictParseInt(dashParts[0], `range start of field "${name}"`);
    const end   = strictParseInt(dashParts[1], `range end of field "${name}"`);
    assertInRange(start, min, max, `range start of field "${name}"`);
    assertInRange(end,   min, max, `range end of field "${name}"`);
    if (start > end) {
      throw new Error(`Range start ${start} exceeds end ${end} in field "${name}"`);
    }
    return expandStep(start, end, 1);
  }

  // ── Single number ─────────────────────────────────────────────────────────
  const value = strictParseInt(segment, `value of field "${name}"`);
  assertInRange(value, min, max, `field "${name}"`);
  return [value];
}

function parseField(field: string, config: FieldConfig): number[] {
  if (!field || field.trim() === "") {
    throw new Error(`Field "${config.name}" must not be empty`);
  }

  // ── Comma list: handled by splitting and recursing into parseSegment ───────
  if (field.includes(",")) {
    const segments = field.split(",");
    const seen = new Set<number>();

    for (const segment of segments) {
      const trimmed = segment.trim();
      if (trimmed === "") {
        throw new Error(
          `Empty segment in comma-separated list for field "${config.name}": "${field}"`
        );
      }
      for (const v of parseSegment(trimmed, config)) {
        seen.add(v);
      }
    }

    return Array.from(seen).sort((a, b) => a - b);
  }

  return parseSegment(field.trim(), config);
}

export default function parseCron(expression: string): CronExpression {
  if (typeof expression !== "string" || expression.trim() === "") {
    throw new Error("Cron expression must be a non-empty string");
  }

  const fields = expression.trim().split(/\s+/);

  if (fields.length !== 5) {
    throw new Error(
      `A cron expression requires exactly 5 fields; got ${fields.length}: "${expression}"`
    );
  }

  const [minuteField, hourField, dayOfMonthField, monthField, dayOfWeekField] = fields;

  return {
    minute:     parseField(minuteField,     FIELD_CONFIGS[0]),
    hour:       parseField(hourField,       FIELD_CONFIGS[1]),
    dayOfMonth: parseField(dayOfMonthField, FIELD_CONFIGS[2]),
    month:      parseField(monthField,      FIELD_CONFIGS[3]),
    dayOfWeek:  parseField(dayOfWeekField,  FIELD_CONFIGS[4]),
  };
}

type Scalar = string | number | boolean | null | undefined | bigint | symbol;

function isTraversable(value: unknown): value is Record<string | number, unknown> {
  if (value === null || typeof value !== "object") return false;
  if (value instanceof Date) return false;
  if (value instanceof RegExp) return false;
  if (value instanceof Map) return false;
  if (value instanceof Set) return false;
  if (value instanceof ArrayBuffer) return false;
  return true;
}

function flatten(
  value: Record<string | number, unknown>,
  prefix: string,
  result: Record<string, unknown>,
  ancestors: Set<object>
): void {
  if (ancestors.has(value)) {
    throw new TypeError(
      `Circular reference detected${prefix ? ` at key "${prefix}"` : ""}`
    );
  }

  const keys = Object.keys(value);

  if (keys.length === 0) {
    if (prefix) result[prefix] = value;
    return;
  }

  ancestors.add(value);

  for (const key of keys) {
    if (!Object.prototype.hasOwnProperty.call(value, key)) continue;

    const child = (value as Record<string, unknown>)[key];
    const childKey = prefix ? `${prefix}.${key}` : key;

    if (isTraversable(child)) {
      flatten(child, childKey, result, ancestors);
    } else {
      result[childKey] = child as Scalar;
    }
  }

  ancestors.delete(value);
}

export default function flattenObject(
  obj: Record<string, unknown>
): Record<string, unknown> {
  if (obj === null || typeof obj !== "object") {
    throw new TypeError(
      `flattenObject expects a non-null object, received ${obj === null ? "null" : typeof obj}`
    );
  }

  const result: Record<string, unknown> = {};
  flatten(obj, "", result, new Set());
  return result;
}

interface CronResult {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<keyof CronResult, [number, number]> = {
  minute: [0, 59],
  hour: [0, 23],
  dayOfMonth: [1, 31],
  month: [1, 12],
  dayOfWeek: [0, 6],
};

function range(start: number, end: number): number[] {
  const result: number[] = [];
  for (let i = start; i <= end; i++) result.push(i);
  return result;
}

function unique(values: number[]): number[] {
  return [...new Set(values)].sort((a, b) => a - b);
}

function clamp(value: number, min: number, max: number): number {
  if (value < min || value > max) {
    throw new RangeError(`Value ${value} out of range [${min}, ${max}]`);
  }
  return value;
}

function parseSegment(segment: string, min: number, max: number): number[] {
  // Wildcard
  if (segment === "*") {
    return range(min, max);
  }

  // Step with wildcard: */n
  if (segment.startsWith("*/")) {
    const step = parseInt(segment.slice(2), 10);
    if (isNaN(step) || step <= 0) {
      throw new Error(`Invalid step value in segment: ${segment}`);
    }
    return range(min, max).filter((v) => (v - min) % step === 0);
  }

  // Step with range: n-m/s
  if (segment.includes("/")) {
    const [rangePart, stepPart] = segment.split("/");
    const step = parseInt(stepPart, 10);
    if (isNaN(step) || step <= 0) {
      throw new Error(`Invalid step value in segment: ${segment}`);
    }
    if (!rangePart.includes("-")) {
      throw new Error(`Invalid step expression: ${segment}`);
    }
    const [startStr, endStr] = rangePart.split("-");
    const start = clamp(parseInt(startStr, 10), min, max);
    const end = clamp(parseInt(endStr, 10), min, max);
    if (start > end) throw new Error(`Invalid range ${start}-${end}`);
    return range(start, end).filter((v) => (v - start) % step === 0);
  }

  // Range: n-m
  if (segment.includes("-")) {
    const [startStr, endStr] = segment.split("-");
    const start = clamp(parseInt(startStr, 10), min, max);
    const end = clamp(parseInt(endStr, 10), min, max);
    if (start > end) throw new Error(`Invalid range ${start}-${end}`);
    return range(start, end);
  }

  // Single number
  const num = parseInt(segment, 10);
  if (isNaN(num)) {
    throw new Error(`Invalid cron segment: ${segment}`);
  }
  return [clamp(num, min, max)];
}

function parseField(field: string, min: number, max: number): number[] {
  const parts = field.split(",");
  const values: number[] = [];
  for (const part of parts) {
    const trimmed = part.trim();
    if (!trimmed) throw new Error(`Empty part in field: ${field}`);
    values.push(...parseSegment(trimmed, min, max));
  }
  return unique(values);
}

export default function parseCron(expression: string): CronResult {
  const fields = expression.trim().split(/\s+/);
  if (fields.length !== 5) {
    throw new Error(
      `Invalid cron expression: expected 5 fields, got ${fields.length}`
    );
  }

  const [minuteField, hourField, domField, monthField, dowField] = fields;
  const keys = Object.keys(FIELD_RANGES) as (keyof CronResult)[];

  return {
    minute: parseField(minuteField, ...FIELD_RANGES.minute),
    hour: parseField(hourField, ...FIELD_RANGES.hour),
    dayOfMonth: parseField(domField, ...FIELD_RANGES.dayOfMonth),
    month: parseField(monthField, ...FIELD_RANGES.month),
    dayOfWeek: parseField(dowField, ...FIELD_RANGES.dayOfWeek),
  };
}

type CronResult = {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
};

const FIELD_RANGES: Record<keyof CronResult, [number, number]> = {
  minute: [0, 59],
  hour: [0, 23],
  dayOfMonth: [1, 31],
  month: [1, 12],
  dayOfWeek: [0, 6],
};

function range(from: number, to: number): number[] {
  const result: number[] = [];
  for (let i = from; i <= to; i++) result.push(i);
  return result;
}

function parseField(field: string, min: number, max: number): number[] {
  const allValues = range(min, max);

  // Comma-separated list
  if (field.includes(",")) {
    const values = field.split(",").flatMap((part) => parseField(part.trim(), min, max));
    const unique = [...new Set(values)].sort((a, b) => a - b);
    return unique;
  }

  // Wildcard
  if (field === "*") {
    return allValues;
  }

  // Step value: */step or start-end/step
  if (field.includes("/")) {
    const [rangeStr, stepStr] = field.split("/");
    const step = parseInt(stepStr, 10);

    if (isNaN(step) || step <= 0) {
      throw new Error(`Invalid step value: "${stepStr}"`);
    }

    let from = min;
    let to = max;

    if (rangeStr !== "*") {
      if (rangeStr.includes("-")) {
        const [startStr, endStr] = rangeStr.split("-");
        from = parseInt(startStr, 10);
        to = parseInt(endStr, 10);
      } else {
        from = parseInt(rangeStr, 10);
      }
    }

    if (isNaN(from) || isNaN(to)) {
      throw new Error(`Invalid range in step expression: "${field}"`);
    }

    if (from < min || to > max || from > to) {
      throw new Error(
        `Step range ${from}-${to} is out of bounds [${min}, ${max}]`
      );
    }

    const result: number[] = [];
    for (let i = from; i <= to; i += step) result.push(i);
    return result;
  }

  // Range: start-end
  if (field.includes("-")) {
    const [startStr, endStr] = field.split("-");
    const from = parseInt(startStr, 10);
    const to = parseInt(endStr, 10);

    if (isNaN(from) || isNaN(to)) {
      throw new Error(`Invalid range: "${field}"`);
    }

    if (from < min || to > max || from > to) {
      throw new Error(
        `Range ${from}-${to} is out of bounds [${min}, ${max}]`
      );
    }

    return range(from, to);
  }

  // Single number
  const value = parseInt(field, 10);

  if (isNaN(value)) {
    throw new Error(`Invalid cron field value: "${field}"`);
  }

  if (value < min || value > max) {
    throw new Error(`Value ${value} is out of bounds [${min}, ${max}]`);
  }

  return [value];
}

export default function parseCron(expression: string): CronResult {
  if (typeof expression !== "string") {
    throw new Error("Cron expression must be a string");
  }

  const fields = expression.trim().split(/\s+/);

  if (fields.length !== 5) {
    throw new Error(
      `Cron expression must have exactly 5 fields, got ${fields.length}`
    );
  }

  const [minuteStr, hourStr, dayOfMonthStr, monthStr, dayOfWeekStr] = fields;
  const fieldNames = Object.keys(FIELD_RANGES) as (keyof CronResult)[];
  const fieldStrings = [minuteStr, hourStr, dayOfMonthStr, monthStr, dayOfWeekStr];

  const result = {} as CronResult;

  for (let i = 0; i < fieldNames.length; i++) {
    const name = fieldNames[i];
    const [min, max] = FIELD_RANGES[name];
    try {
      result[name] = parseField(fieldStrings[i], min, max);
    } catch (err) {
      throw new Error(
        `Invalid value for field "${name}": ${(err as Error).message}`
      );
    }
  }

  return result;
}

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: Primitive | NestedObject | Array<unknown> };
type FlatObject = { [key: string]: Primitive };

function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: FlatObject = {}
): FlatObject {
  if (obj === null || obj === undefined || typeof obj !== "object") {
    if (prefix) result[prefix] = obj as Primitive;
    return result;
  }

  if (Array.isArray(obj)) {
    if (obj.length === 0) {
      if (prefix) result[prefix] = null;
    } else {
      obj.forEach((item, index) => {
        const key = prefix ? `${prefix}.${index}` : `${index}`;
        flattenObject(item as NestedObject, key, result);
      });
    }
    return result;
  }

  const keys = Object.keys(obj);

  if (keys.length === 0) {
    if (prefix) result[prefix] = null;
    return result;
  }

  for (const k of keys) {
    const value = obj[k];
    const newKey = prefix ? `${prefix}.${k}` : k;

    if (
      value !== null &&
      value !== undefined &&
      typeof value === "object"
    ) {
      flattenObject(value as NestedObject, newKey, result);
    } else {
      result[newKey] = value as Primitive;
    }
  }

  return result;
}

export default flattenObject;

export interface CronExpression {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldConfig {
  readonly min: number;
  readonly max: number;
  readonly name: string;
}

const FIELD_CONFIGS = [
  { min: 0, max: 59, name: "minute" },
  { min: 0, max: 23, name: "hour" },
  { min: 1, max: 31, name: "dayOfMonth" },
  { min: 1, max: 12, name: "month" },
  { min: 0, max: 7,  name: "dayOfWeek" },
] as const satisfies FieldConfig[];

function parseNonNegativeInteger(raw: string, fieldName: string): number {
  const trimmed = raw.trim();
  if (!/^\d+$/.test(trimmed)) {
    throw new Error(
      `Invalid token "${raw}" in field "${fieldName}": expected a non-negative integer`
    );
  }
  const n = parseInt(trimmed, 10);
  if (!Number.isFinite(n)) {
    throw new Error(`Parsed non-finite value from "${raw}" in field "${fieldName}"`);
  }
  return n;
}

function assertInRange(value: number, min: number, max: number, fieldName: string): void {
  if (value < min || value > max) {
    throw new Error(
      `Value ${value} out of valid range [${min}, ${max}] for field "${fieldName}"`
    );
  }
}

function buildRange(
  start: number,
  end: number,
  step: number,
  min: number,
  max: number,
  fieldName: string
): number[] {
  if (step <= 0) {
    throw new Error(`Step must be a positive integer in field "${fieldName}", got ${step}`);
  }
  assertInRange(start, min, max, fieldName);
  assertInRange(end, min, max, fieldName);
  if (start > end) {
    throw new Error(
      `Range start (${start}) must not exceed range end (${end}) in field "${fieldName}"`
    );
  }
  const values: number[] = [];
  for (let i = start; i <= end; i += step) {
    values.push(i);
  }
  return values;
}

function parseSegment(segment: string, config: FieldConfig): number[] {
  const { min, max, name } = config;
  const s = segment.trim();

  if (!s) {
    throw new Error(`Empty segment encountered in field "${name}"`);
  }

  // Step value: */step  |  start-end/step  |  start/step
  const slashIndex = s.indexOf("/");
  if (slashIndex !== -1) {
    const lhs = s.substring(0, slashIndex);
    const rhs = s.substring(slashIndex + 1);

    if (!rhs || rhs.includes("/")) {
      throw new Error(`Malformed step expression "${s}" in field "${name}"`);
    }

    const step = parseNonNegativeInteger(rhs, name);
    if (step === 0) {
      throw new Error(`Step value must not be zero in field "${name}"`);
    }

    if (lhs === "*") {
      return buildRange(min, max, step, min, max, name);
    }

    const dashIndex = lhs.indexOf("-");
    if (dashIndex !== -1) {
      const start = parseNonNegativeInteger(lhs.substring(0, dashIndex), name);
      const end   = parseNonNegativeInteger(lhs.substring(dashIndex + 1), name);
      return buildRange(start, end, step, min, max, name);
    }

    // start/step — expand from start to field max
    const start = parseNonNegativeInteger(lhs, name);
    return buildRange(start, max, step, min, max, name);
  }

  // Wildcard
  if (s === "*") {
    return buildRange(min, max, 1, min, max, name);
  }

  // Range: start-end
  const dashIndex = s.indexOf("-");
  if (dashIndex !== -1) {
    const startRaw = s.substring(0, dashIndex);
    const endRaw   = s.substring(dashIndex + 1);
    if (!startRaw || !endRaw || endRaw.includes("-")) {
      throw new Error(`Malformed range "${s}" in field "${name}"`);
    }
    const start = parseNonNegativeInteger(startRaw, name);
    const end   = parseNonNegativeInteger(endRaw,   name);
    return buildRange(start, end, 1, min, max, name);
  }

  // Single value
  const value = parseNonNegativeInteger(s, name);
  assertInRange(value, min, max, name);
  return [value];
}

function parseField(raw: string, config: FieldConfig): number[] {
  if (!raw || !raw.trim()) {
    throw new Error(`Field "${config.name}" is empty`);
  }

  const segments = raw.split(",");
  if (segments.length === 0) {
    throw new Error(`Field "${config.name}" produced no segments`);
  }

  const seen = new Set<number>();

  for (const segment of segments) {
    const values = parseSegment(segment, config);
    for (const v of values) {
      seen.add(v);
    }
  }

  // Normalise: in dayOfWeek both 0 and 7 represent Sunday
  if (config.name === "dayOfWeek" && seen.has(7)) {
    seen.delete(7);
    seen.add(0);
  }

  return Array.from(seen).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronExpression {
  if (expression === null || expression === undefined) {
    throw new Error("Cron expression must not be null or undefined");
  }
  if (typeof expression !== "string") {
    throw new Error(`Cron expression must be a string, received ${typeof expression}`);
  }

  const trimmed = expression.trim();
  if (!trimmed) {
    throw new Error("Cron expression must not be blank");
  }

  const fields = trimmed.split(/\s+/);

  if (fields.length !== 5) {
    throw new Error(
      `Cron expression must have exactly 5 whitespace-separated fields, ` +
      `got ${fields.length} in: "${expression}"`
    );
  }

  const [minuteRaw, hourRaw, domRaw, monthRaw, dowRaw] = fields;

  return {
    minute:     parseField(minuteRaw, FIELD_CONFIGS[0]),
    hour:       parseField(hourRaw,   FIELD_CONFIGS[1]),
    dayOfMonth: parseField(domRaw,    FIELD_CONFIGS[2]),
    month:      parseField(monthRaw,  FIELD_CONFIGS[3]),
    dayOfWeek:  parseField(dowRaw,    FIELD_CONFIGS[4]),
  };
}

type Primitive = string | number | boolean | null | undefined | bigint | symbol;

type FlattenedObject = Record<string, Primitive>;

function isPlainObject(value: unknown): value is Record<string, unknown> {
  if (value === null || typeof value !== "object") return false;
  if (Array.isArray(value)) return false;
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function flattenObject(
  input: Record<string, unknown>,
  prefix: string = "",
  output: FlattenedObject = {},
  visited: WeakSet<object> = new WeakSet()
): FlattenedObject {
  if (input === null || typeof input !== "object") {
    return output;
  }

  if (visited.has(input)) {
    return output;
  }

  visited.add(input);

  for (const key of Object.keys(input)) {
    if (!Object.prototype.hasOwnProperty.call(input, key)) continue;

    const value = input[key];
    const flatKey = prefix.length > 0 ? `${prefix}.${key}` : key;

    if (isPlainObject(value) && Object.keys(value).length > 0) {
      flattenObject(value, flatKey, output, visited);
    } else if (isPlainObject(value) && Object.keys(value).length === 0) {
      output[flatKey] = undefined;
    } else {
      output[flatKey] = value as Primitive;
    }
  }

  visited.delete(input);

  return output;
}

export default flattenObject;

type ParsedCron = {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
};

type FieldConfig = {
  readonly name: string;
  readonly min: number;
  readonly max: number;
};

const FIELD_CONFIGS = [
  { name: "minute", min: 0, max: 59 },
  { name: "hour", min: 0, max: 23 },
  { name: "dayOfMonth", min: 1, max: 31 },
  { name: "month", min: 1, max: 12 },
  { name: "dayOfWeek", min: 0, max: 7 }, // 7 allowed as alias for Sunday (0)
] as const satisfies FieldConfig[];

function isNonNegativeInteger(s: string): boolean {
  return /^\d+$/.test(s);
}

function parseIntStrict(s: string, fieldName: string, token: string): number {
  if (!isNonNegativeInteger(s)) {
    throw new Error(
      `Invalid ${fieldName} field: expected non-negative integer, got "${s}" in "${token}"`
    );
  }
  return parseInt(s, 10);
}

function assertInBounds(
  value: number,
  min: number,
  max: number,
  fieldName: string,
  token: string
): void {
  if (value < min || value > max) {
    throw new Error(
      `Invalid ${fieldName} field: value ${value} is out of bounds [${min}, ${max}] in "${token}"`
    );
  }
}

function expandRange(
  from: number,
  to: number,
  step: number,
  fieldName: string,
  token: string
): number[] {
  if (from > to) {
    throw new Error(
      `Invalid ${fieldName} field: range start ${from} exceeds end ${to} in "${token}"`
    );
  }
  if (step <= 0) {
    throw new Error(
      `Invalid ${fieldName} field: step must be a positive integer, got ${step} in "${token}"`
    );
  }
  const values: number[] = [];
  for (let i = from; i <= to; i += step) {
    values.push(i);
  }
  return values;
}

function parseSegment(token: string, config: FieldConfig): number[] {
  const { name, min, max } = config;

  // Guard: empty token should never reach here, but be paranoid
  if (token.length === 0) {
    throw new Error(`Invalid ${name} field: empty segment`);
  }

  // Step value: */n, a-b/n, or a/n
  if (token.includes("/")) {
    const slashIndex = token.indexOf("/");
    if (token.indexOf("/", slashIndex + 1) !== -1) {
      throw new Error(
        `Invalid ${name} field: multiple '/' characters in "${token}"`
      );
    }
    const baseStr = token.slice(0, slashIndex);
    const stepStr = token.slice(slashIndex + 1);

    if (stepStr.length === 0) {
      throw new Error(`Invalid ${name} field: missing step value in "${token}"`);
    }
    const step = parseIntStrict(stepStr, name, token);
    if (step === 0) {
      throw new Error(
        `Invalid ${name} field: step value must not be zero in "${token}"`
      );
    }

    if (baseStr === "*") {
      return expandRange(min, max, step, name, token);
    }

    if (baseStr.includes("-")) {
      const dashIndex = baseStr.indexOf("-");
      if (baseStr.indexOf("-", dashIndex + 1) !== -1) {
        throw new Error(
          `Invalid ${name} field: multiple '-' characters in range part of "${token}"`
        );
      }
      const from = parseIntStrict(baseStr.slice(0, dashIndex), name, token);
      const to = parseIntStrict(baseStr.slice(dashIndex + 1), name, token);
      assertInBounds(from, min, max, name, token);
      assertInBounds(to, min, max, name, token);
      return expandRange(from, to, step, name, token);
    }

    // "n/step" — start from n, step through to max
    const from = parseIntStrict(baseStr, name, token);
    assertInBounds(from, min, max, name, token);
    return expandRange(from, max, step, name, token);
  }

  // Wildcard
  if (token === "*") {
    return expandRange(min, max, 1, name, token);
  }

  // Range: a-b
  if (token.includes("-")) {
    const dashIndex = token.indexOf("-");
    if (token.indexOf("-", dashIndex + 1) !== -1) {
      throw new Error(
        `Invalid ${name} field: multiple '-' characters in "${token}"`
      );
    }
    const from = parseIntStrict(token.slice(0, dashIndex), name, token);
    const to = parseIntStrict(token.slice(dashIndex + 1), name, token);
    assertInBounds(from, min, max, name, token);
    assertInBounds(to, min, max, name, token);
    return expandRange(from, to, 1, name, token);
  }

  // Single value
  const value = parseIntStrict(token, name, token);
  assertInBounds(value, min, max, name, token);
  return [value];
}

function parseField(raw: string, config: FieldConfig): number[] {
  if (raw.length === 0) {
    throw new Error(`Invalid ${config.name} field: field must not be empty`);
  }

  const parts = raw.split(",");
  if (parts.some((p) => p.length === 0)) {
    throw new Error(
      `Invalid ${config.name} field: empty segment in comma-separated list "${raw}"`
    );
  }

  const values = parts.flatMap((part) => parseSegment(part, config));
  const unique = [...new Set(values)].sort((a, b) => a - b);
  return unique;
}

function normalizeDayOfWeek(values: number[]): number[] {
  // 0 and 7 both represent Sunday — collapse 7 → 0
  const normalized = values.map((v) => (v === 7 ? 0 : v));
  return [...new Set(normalized)].sort((a, b) => a - b);
}

export default function parseCron(expression: string): ParsedCron {
  if (typeof expression !== "string") {
    throw new TypeError(
      `parseCron expects a string, got ${typeof expression}`
    );
  }

  const trimmed = expression.trim();
  if (trimmed.length === 0) {
    throw new Error("Cron expression must not be empty");
  }

  const fields = trimmed.split(/\s+/);
  if (fields.length !== 5) {
    throw new Error(
      `Cron expression must have exactly 5 fields (minute hour dayOfMonth month dayOfWeek), got ${fields.length}`
    );
  }

  const [minuteRaw, hourRaw, domRaw, monthRaw, dowRaw] = fields;

  const rawDow = parseField(dowRaw, FIELD_CONFIGS[4]);

  return {
    minute: parseField(minuteRaw, FIELD_CONFIGS[0]),
    hour: parseField(hourRaw, FIELD_CONFIGS[1]),
    dayOfMonth: parseField(domRaw, FIELD_CONFIGS[2]),
    month: parseField(monthRaw, FIELD_CONFIGS[3]),
    dayOfWeek: normalizeDayOfWeek(rawDow),
  };
}

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: Primitive | NestedObject | Array<unknown> };
type FlatObject = { [key: string]: Primitive };

function flattenObject(
  obj: NestedObject,
  prefix: string = "",
  result: FlatObject = {}
): FlatObject {
  if (obj === null || obj === undefined || typeof obj !== "object") {
    if (prefix) result[prefix] = obj as Primitive;
    return result;
  }

  if (Array.isArray(obj)) {
    if (prefix) result[prefix] = JSON.stringify(obj);
    return result;
  }

  const keys = Object.keys(obj);

  if (keys.length === 0) {
    if (prefix) result[prefix] = "{}";
    return result;
  }

  for (const key of keys) {
    const value = obj[key];
    const newKey = prefix ? `${prefix}.${key}` : key;

    if (
      value !== null &&
      value !== undefined &&
      typeof value === "object" &&
      !Array.isArray(value)
    ) {
      flattenObject(value as NestedObject, newKey, result);
    } else if (Array.isArray(value)) {
      result[newKey] = JSON.stringify(value);
    } else {
      result[newKey] = value as Primitive;
    }
  }

  return result;
}

export default flattenObject;

interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<keyof CronFields, [number, number]> = {
  minute: [0, 59],
  hour: [0, 23],
  dayOfMonth: [1, 31],
  month: [1, 12],
  dayOfWeek: [0, 6],
};

function expandField(expr: string, min: number, max: number): number[] {
  const results = new Set<number>();

  for (const part of expr.split(",")) {
    const trimmed = part.trim();

    if (trimmed === "*") {
      for (let i = min; i <= max; i++) results.add(i);
      continue;
    }

    const stepMatch = trimmed.match(/^(\*|(\d+)-(\d+))\/(\d+)$/);
    if (stepMatch) {
      const step = parseInt(stepMatch[4], 10);
      if (step <= 0) throw new Error(`Invalid step value: ${step}`);
      const rangeMin = stepMatch[1] === "*" ? min : parseInt(stepMatch[2], 10);
      const rangeMax = stepMatch[1] === "*" ? max : parseInt(stepMatch[3], 10);
      validateRange(rangeMin, rangeMax, min, max);
      for (let i = rangeMin; i <= rangeMax; i += step) results.add(i);
      continue;
    }

    const rangeMatch = trimmed.match(/^(\d+)-(\d+)$/);
    if (rangeMatch) {
      const lo = parseInt(rangeMatch[1], 10);
      const hi = parseInt(rangeMatch[2], 10);
      validateRange(lo, hi, min, max);
      for (let i = lo; i <= hi; i++) results.add(i);
      continue;
    }

    if (/^\d+$/.test(trimmed)) {
      const val = parseInt(trimmed, 10);
      if (val < min || val > max) {
        throw new Error(`Value ${val} out of range [${min}, ${max}]`);
      }
      results.add(val);
      continue;
    }

    throw new Error(`Invalid cron field expression: "${trimmed}"`);
  }

  return Array.from(results).sort((a, b) => a - b);
}

function validateRange(lo: number, hi: number, min: number, max: number): void {
  if (lo > hi) throw new Error(`Invalid range: ${lo}-${hi} (start > end)`);
  if (lo < min || hi > max) {
    throw new Error(`Range ${lo}-${hi} out of bounds [${min}, ${max}]`);
  }
}

export default function parseCron(expression: string): CronFields {
  if (typeof expression !== "string") {
    throw new Error("Cron expression must be a string");
  }

  const parts = expression.trim().split(/\s+/);
  if (parts.length !== 5) {
    throw new Error(
      `Expected 5 fields, got ${parts.length}: "${expression}"`
    );
  }

  const fieldNames = Object.keys(FIELD_RANGES) as (keyof CronFields)[];

  return fieldNames.reduce((acc, field, index) => {
    const [min, max] = FIELD_RANGES[field];
    acc[field] = expandField(parts[index], min, max);
    return acc;
  }, {} as CronFields);
}

type CronResult = {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
};

const FIELD_RANGES: Record<keyof CronResult, [number, number]> = {
  minute: [0, 59],
  hour: [0, 23],
  dayOfMonth: [1, 31],
  month: [1, 12],
  dayOfWeek: [0, 6],
};

function range(start: number, end: number): number[] {
  const result: number[] = [];
  for (let i = start; i <= end; i++) result.push(i);
  return result;
}

function parseField(field: string, min: number, max: number): number[] {
  const allValues = range(min, max);

  if (field === "*") return allValues;

  if (field.startsWith("*/")) {
    const step = parseInt(field.slice(2), 10);
    if (isNaN(step) || step <= 0) throw new Error(`Invalid step value: ${field}`);
    return allValues.filter((v) => (v - min) % step === 0);
  }

  if (field.includes(",")) {
    const parts = field.split(",");
    const values = new Set<number>();
    for (const part of parts) {
      for (const v of parseField(part.trim(), min, max)) values.add(v);
    }
    return [...values].sort((a, b) => a - b);
  }

  if (field.includes("/")) {
    const [rangePart, stepPart] = field.split("/");
    const step = parseInt(stepPart, 10);
    if (isNaN(step) || step <= 0) throw new Error(`Invalid step value: ${field}`);
    const base = rangePart === "*" ? allValues : parseField(rangePart, min, max);
    const start = base[0];
    return base.filter((v) => (v - start) % step === 0);
  }

  if (field.includes("-")) {
    const [startStr, endStr] = field.split("-");
    const start = parseInt(startStr, 10);
    const end = parseInt(endStr, 10);
    if (isNaN(start) || isNaN(end)) throw new Error(`Invalid range: ${field}`);
    if (start < min || end > max || start > end) {
      throw new Error(`Range out of bounds: ${field} (expected ${min}-${max})`);
    }
    return range(start, end);
  }

  const num = parseInt(field, 10);
  if (isNaN(num)) throw new Error(`Invalid value: ${field}`);
  if (num < min || num > max) {
    throw new Error(`Value ${num} out of range (expected ${min}-${max})`);
  }
  return [num];
}

export default function parseCron(expression: string): CronResult {
  const parts = expression.trim().split(/\s+/);
  if (parts.length !== 5) {
    throw new Error(`Expected 5 fields, got ${parts.length}`);
  }

  const [minuteStr, hourStr, domStr, monthStr, dowStr] = parts;
  const fields = Object.keys(FIELD_RANGES) as (keyof CronResult)[];
  const values = [minuteStr, hourStr, domStr, monthStr, dowStr];

  const result = {} as CronResult;
  for (let i = 0; i < fields.length; i++) {
    const key = fields[i];
    const [min, max] = FIELD_RANGES[key];
    result[key] = parseField(values[i], min, max);
  }

  return result;
}

type Primitive = string | number | boolean | null | undefined | bigint | symbol;
type FlatValue = Primitive | Date | RegExp | Function | unknown[];

interface NestedObject {
  [key: string]: NestedObject | FlatValue;
}

type FlattenedObject = Record<string, FlatValue>;

const isPlainObject = (value: unknown): value is NestedObject => {
  if (value === null || typeof value !== "object") return false;
  if (Array.isArray(value)) return false;
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
};

const flattenObject = (
  input: NestedObject,
  prefix: string = "",
  seen: WeakSet<object> = new WeakSet(),
  result: FlattenedObject = {}
): FlattenedObject => {
  if (!isPlainObject(input)) return result;

  if (seen.has(input)) return result;
  seen.add(input);

  const keys = Object.keys(input);

  if (keys.length === 0) {
    if (prefix !== "") {
      result[prefix] = {};
    }
    return result;
  }

  for (const key of keys) {
    const value = input[key];
    const newKey = prefix !== "" ? `${prefix}.${key}` : key;

    if (isPlainObject(value)) {
      const childKeys = Object.keys(value);
      if (childKeys.length === 0) {
        result[newKey] = {};
      } else {
        flattenObject(value, newKey, seen, result);
      }
    } else {
      result[newKey] = value as FlatValue;
    }
  }

  return result;
};

export default flattenObject;

export interface CronExpression {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

type FieldName = keyof CronExpression;

const FIELD_RANGES: Record<FieldName, { min: number; max: number }> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 6  },
};

const FIELD_ORDER: FieldName[] = ["minute", "hour", "dayOfMonth", "month", "dayOfWeek"];

function buildRange(start: number, end: number): number[] {
  const result: number[] = [];
  for (let i = start; i <= end; i++) result.push(i);
  return result;
}

function assertInteger(raw: string, context: string): number {
  const trimmed = raw.trim();
  if (!/^-?\d+$/.test(trimmed)) {
    throw new Error(`Non-integer value "${trimmed}" in field: ${context}`);
  }
  return parseInt(trimmed, 10);
}

function assertInBounds(value: number, min: number, max: number, context: string): void {
  if (value < min || value > max) {
    throw new Error(
      `Value ${value} is out of bounds [${min}, ${max}] in field: ${context}`
    );
  }
}

function assertRangeOrder(start: number, end: number, context: string): void {
  if (start > end) {
    throw new Error(
      `Range start ${start} exceeds range end ${end} in field: ${context}`
    );
  }
}

function parseSegment(segment: string, min: number, max: number): number[] {
  const context = segment;

  // Step expression: base/step (e.g. "*/15", "0-30/5", "5/10")
  if (segment.includes("/")) {
    const slashCount = (segment.match(/\//g) ?? []).length;
    if (slashCount !== 1) {
      throw new Error(`Invalid step expression: ${context}`);
    }

    const [basePart, stepPart] = segment.split("/");
    const step = assertInteger(stepPart, context);

    if (step <= 0) {
      throw new Error(`Step value must be a positive integer in field: ${context}`);
    }

    let rangeMin = min;
    let rangeMax = max;

    if (basePart === "*") {
      rangeMin = min;
      rangeMax = max;
    } else if (basePart.includes("-")) {
      const dashParts = basePart.split("-");
      if (dashParts.length !== 2) {
        throw new Error(`Invalid range in step expression: ${context}`);
      }
      rangeMin = assertInteger(dashParts[0], context);
      rangeMax = assertInteger(dashParts[1], context);
      assertRangeOrder(rangeMin, rangeMax, context);
      assertInBounds(rangeMin, min, max, context);
      assertInBounds(rangeMax, min, max, context);
    } else {
      rangeMin = assertInteger(basePart, context);
      assertInBounds(rangeMin, min, max, context);
      rangeMax = max;
    }

    const result: number[] = [];
    for (let i = rangeMin; i <= rangeMax; i += step) {
      result.push(i);
    }
    return result;
  }

  // Wildcard
  if (segment === "*") {
    return buildRange(min, max);
  }

  // Range: "a-b"
  if (segment.includes("-")) {
    const dashParts = segment.split("-");
    if (dashParts.length !== 2) {
      throw new Error(`Invalid range expression: ${context}`);
    }
    const start = assertInteger(dashParts[0], context);
    const end   = assertInteger(dashParts[1], context);
    assertRangeOrder(start, end, context);
    assertInBounds(start, min, max, context);
    assertInBounds(end, min, max, context);
    return buildRange(start, end);
  }

  // Single integer
  const value = assertInteger(segment, context);
  assertInBounds(value, min, max, context);
  return [value];
}

function parseField(field: string, min: number, max: number): number[] {
  if (typeof field !== "string" || field.trim().length === 0) {
    throw new Error(`Field value must be a non-empty string, received: ${JSON.stringify(field)}`);
  }

  const trimmed = field.trim();

  // Comma-separated list — each segment is parsed independently
  if (trimmed.includes(",")) {
    const segments = trimmed.split(",");
    const seen = new Set<number>();

    for (const segment of segments) {
      const segTrimmed = segment.trim();
      if (segTrimmed.length === 0) {
        throw new Error(`Empty segment in comma-separated list: "${trimmed}"`);
      }
      for (const v of parseSegment(segTrimmed, min, max)) {
        seen.add(v);
      }
    }

    return Array.from(seen).sort((a, b) => a - b);
  }

  return parseSegment(trimmed, min, max);
}

export default function parseCron(expression: string): CronExpression {
  if (typeof expression !== "string") {
    throw new Error(`Cron expression must be a string, received: ${typeof expression}`);
  }

  const trimmed = expression.trim();

  if (trimmed.length === 0) {
    throw new Error("Cron expression must not be empty");
  }

  const parts = trimmed.split(/\s+/);

  if (parts.length !== 5) {
    throw new Error(
      `Cron expression must contain exactly 5 fields separated by whitespace, got ${parts.length}: "${expression}"`
    );
  }

  const result = {} as CronExpression;

  for (let i = 0; i < FIELD_ORDER.length; i++) {
    const name = FIELD_ORDER[i];
    const { min, max } = FIELD_RANGES[name];
    try {
      result[name] = parseField(parts[i], min, max);
    } catch (err) {
      const message = err instanceof Error ? err.message : String(err);
      throw new Error(`Invalid ${name} field ("${parts[i]}"): ${message}`);
    }
  }

  return result;
}

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: Primitive | NestedObject | Array<unknown> };
type FlatObject = { [key: string]: Primitive };

function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: FlatObject = {}
): FlatObject {
  if (obj === null || typeof obj !== "object" || Array.isArray(obj)) {
    if (prefix) result[prefix] = obj as Primitive;
    return result;
  }

  const keys = Object.keys(obj);

  if (keys.length === 0) {
    if (prefix) result[prefix] = null;
    return result;
  }

  for (const key of keys) {
    const value = obj[key];
    const newKey = prefix ? `${prefix}.${key}` : key;

    if (
      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value)
    ) {
      flattenObject(value as NestedObject, newKey, result);
    } else if (Array.isArray(value)) {
      for (let i = 0; i < value.length; i++) {
        const arrKey = `${newKey}.${i}`;
        const item = value[i];
        if (item !== null && typeof item === "object" && !Array.isArray(item)) {
          flattenObject(item as NestedObject, arrKey, result);
        } else {
          result[arrKey] = item as Primitive;
        }
      }
    } else {
      result[newKey] = value as Primitive;
    }
  }

  return result;
}

export default flattenObject;

type Scalar = string | number | boolean | null | undefined | bigint | symbol;
type LeafValue = Scalar | Date | RegExp | Function | unknown[];

type FlattenResult = Record<string, LeafValue>;

function isPlainObject(value: unknown): value is Record<string, unknown> {
  if (value === null || typeof value !== "object") return false;
  if (Array.isArray(value)) return false;
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function flattenInternal(
  obj: Record<string, unknown>,
  prefix: string,
  seen: WeakSet<object>,
  result: FlattenResult
): void {
  if (seen.has(obj)) {
    throw new Error(
      `Circular reference detected${prefix ? ` at key "${prefix}"` : " at root"}`
    );
  }
  seen.add(obj);

  for (const key of Object.keys(obj)) {
    const value = obj[key];
    const flatKey = prefix ? `${prefix}.${key}` : key;

    if (isPlainObject(value)) {
      if (Object.keys(value).length > 0) {
        // Non-empty plain object: recurse and merge into result
        flattenInternal(value, flatKey, seen, result);
      } else {
        // Empty plain object: preserve as leaf to avoid silent key loss
        result[flatKey] = value as Record<string, never>;
      }
    } else {
      // Leaf value: primitives, arrays, Dates, RegExps, class instances, etc.
      result[flatKey] = value as LeafValue;
    }
  }

  // Remove from seen after processing so the same object reference can
  // appear in sibling branches without a false-positive circular ref error
  seen.delete(obj);
}

export default function flattenObject(obj: Record<string, unknown>): FlattenResult {
  if (!isPlainObject(obj)) {
    throw new TypeError(
      `flattenObject expects a plain object, received: ${
        obj === null ? "null" : Array.isArray(obj) ? "array" : typeof obj
      }`
    );
  }

  const result: FlattenResult = {};
  flattenInternal(obj, "", new WeakSet(), result);
  return result;
}

interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<keyof CronFields, { min: number; max: number }> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 6  },
};

function rangeArray(min: number, max: number, step = 1): number[] {
  const result: number[] = [];
  for (let i = min; i <= max; i += step) {
    result.push(i);
  }
  return result;
}

function parseField(
  token: string,
  fieldName: keyof CronFields
): number[] {
  const { min, max } = FIELD_RANGES[fieldName];

  const validate = (value: number): number => {
    if (!Number.isInteger(value) || value < min || value > max) {
      throw new RangeError(
        `Value ${value} out of range [${min}, ${max}] for field "${fieldName}"`
      );
    }
    return value;
  };

  // Comma-separated list — parse each part independently and merge
  if (token.includes(",")) {
    const values = token
      .split(",")
      .flatMap((part) => parseField(part.trim(), fieldName));
    return [...new Set(values)].sort((a, b) => a - b);
  }

  // Step value: */step or start-end/step
  if (token.includes("/")) {
    const [rangePart, stepPart] = token.split("/");
    const step = parseInt(stepPart, 10);
    if (!Number.isInteger(step) || step < 1) {
      throw new Error(`Invalid step value "${stepPart}" in field "${fieldName}"`);
    }

    if (rangePart === "*") {
      return rangeArray(min, max, step);
    }

    if (rangePart.includes("-")) {
      const [startStr, endStr] = rangePart.split("-");
      const start = validate(parseInt(startStr, 10));
      const end   = validate(parseInt(endStr,   10));
      if (start > end) {
        throw new RangeError(
          `Range start ${start} > end ${end} in field "${fieldName}"`
        );
      }
      return rangeArray(start, end, step);
    }

    const start = validate(parseInt(rangePart, 10));
    return rangeArray(start, max, step);
  }

  // Wildcard
  if (token === "*") {
    return rangeArray(min, max);
  }

  // Range: start-end
  if (token.includes("-")) {
    const [startStr, endStr] = token.split("-");
    const start = validate(parseInt(startStr, 10));
    const end   = validate(parseInt(endStr,   10));
    if (start > end) {
      throw new RangeError(
        `Range start ${start} > end ${end} in field "${fieldName}"`
      );
    }
    return rangeArray(start, end);
  }

  // Single numeric value
  const value = parseInt(token, 10);
  if (isNaN(value)) {
    throw new Error(`Invalid token "${token}" in field "${fieldName}"`);
  }
  return [validate(value)];
}

export default function parseCron(expression: string): CronFields {
  if (typeof expression !== "string" || expression.trim() === "") {
    throw new Error("Cron expression must be a non-empty string");
  }

  const parts = expression.trim().split(/\s+/);
  if (parts.length !== 5) {
    throw new Error(
      `Cron expression must have exactly 5 fields, got ${parts.length}`
    );
  }

  const fieldNames = Object.keys(FIELD_RANGES) as (keyof CronFields)[];

  return fieldNames.reduce<CronFields>((acc, fieldName, index) => {
    acc[fieldName] = parseField(parts[index], fieldName);
    return acc;
  }, {} as CronFields);
}

export interface ParsedCron {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

type CronField = keyof ParsedCron;

const FIELD_ORDER: CronField[] = [
  "minute",
  "hour",
  "dayOfMonth",
  "month",
  "dayOfWeek",
];

const FIELD_RANGES: Record<CronField, { min: number; max: number }> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 6  },
};

function parseSegment(
  segment: string,
  fieldMin: number,
  fieldMax: number,
  field: CronField
): number[] {
  if (segment === "") {
    throw new Error(`Empty segment in field "${field}".`);
  }

  const slashIndex = segment.indexOf("/");
  let step = 1;
  let body = segment;

  if (slashIndex !== -1) {
    const stepRaw = segment.slice(slashIndex + 1);
    body = segment.slice(0, slashIndex);

    if (stepRaw === "" || /[^0-9]/.test(stepRaw)) {
      throw new Error(
        `Non-numeric or missing step in "${segment}" for field "${field}".`
      );
    }

    step = parseInt(stepRaw, 10);

    if (step <= 0) {
      throw new Error(
        `Step value must be >= 1, got ${step} in field "${field}".`
      );
    }
  }

  let rangeMin: number;
  let rangeMax: number;

  if (body === "*") {
    rangeMin = fieldMin;
    rangeMax = fieldMax;
  } else if (body.includes("-")) {
    const dashIndex = body.indexOf("-");
    const startRaw = body.slice(0, dashIndex);
    const endRaw = body.slice(dashIndex + 1);

    if (
      startRaw === "" ||
      endRaw === "" ||
      /[^0-9]/.test(startRaw) ||
      /[^0-9]/.test(endRaw)
    ) {
      throw new Error(
        `Non-numeric or malformed range "${body}" in field "${field}".`
      );
    }

    rangeMin = parseInt(startRaw, 10);
    rangeMax = parseInt(endRaw, 10);

    if (rangeMin > rangeMax) {
      throw new Error(
        `Range start ${rangeMin} exceeds range end ${rangeMax} in field "${field}".`
      );
    }

    if (rangeMin < fieldMin || rangeMax > fieldMax) {
      throw new Error(
        `Range ${rangeMin}-${rangeMax} out of bounds [${fieldMin}, ${fieldMax}] for field "${field}".`
      );
    }
  } else {
    if (/[^0-9]/.test(body)) {
      throw new Error(
        `Non-numeric value "${body}" in field "${field}".`
      );
    }

    const val = parseInt(body, 10);

    if (val < fieldMin || val > fieldMax) {
      throw new Error(
        `Value ${val} out of bounds [${fieldMin}, ${fieldMax}] for field "${field}".`
      );
    }

    if (slashIndex === -1) {
      return [val];
    }

    rangeMin = val;
    rangeMax = fieldMax;
  }

  const values: number[] = [];
  for (let i = rangeMin; i <= rangeMax; i += step) {
    values.push(i);
  }
  return values;
}

function parseField(raw: string, field: CronField): number[] {
  const { min, max } = FIELD_RANGES[field];
  const parts = raw.split(",");

  if (parts.length === 0 || (parts.length === 1 && parts[0] === "")) {
    throw new Error(`Field "${field}" is empty.`);
  }

  const seen = new Set<number>();

  for (const part of parts) {
    const trimmed = part.trim();
    if (trimmed === "") {
      throw new Error(`Empty comma-delimited part in field "${field}".`);
    }
    const values = parseSegment(trimmed, min, max, field);
    for (const v of values) {
      seen.add(v);
    }
  }

  return Array.from(seen).sort((a, b) => a - b);
}

export default function parseCron(expression: string): ParsedCron {
  if (typeof expression !== "string") {
    throw new TypeError(`Expected a string, received ${typeof expression}.`);
  }

  const trimmed = expression.trim();

  if (trimmed === "") {
    throw new Error("Cron expression is empty.");
  }

  const fields = trimmed.split(/\s+/);

  if (fields.length !== 5) {
    throw new Error(
      `Expected 5 fields, received ${fields.length}: "${trimmed}".`
    );
  }

  const result = {} as ParsedCron;

  for (let i = 0; i < FIELD_ORDER.length; i++) {
    const field = FIELD_ORDER[i];
    result[field] = parseField(fields[i], field);
  }

  return result;
}

type CronField = "minute" | "hour" | "dayOfMonth" | "month" | "dayOfWeek";

interface CronExpression {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldConfig {
  min: number;
  max: number;
}

const FIELD_CONFIGS: Record<CronField, FieldConfig> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 6  },
};

const FIELD_ORDER: CronField[] = [
  "minute", "hour", "dayOfMonth", "month", "dayOfWeek",
];

function buildRange(start: number, end: number): number[] {
  const result: number[] = [];
  for (let i = start; i <= end; i++) {
    result.push(i);
  }
  return result;
}

function isNonNegativeInteger(str: string): boolean {
  return /^\d+$/.test(str);
}

function parseToken(token: string, config: FieldConfig, fieldName: string): number[] {
  const { min, max } = config;

  // Wildcard: expand to full range
  if (token === "*") {
    return buildRange(min, max);
  }

  // Step: */n — only wildcard-based step is supported in simplified format
  if (token.startsWith("*/")) {
    const stepStr = token.slice(2);
    if (!isNonNegativeInteger(stepStr)) {
      throw new Error(
        `Field "${fieldName}": step in "${token}" must be a positive integer`
      );
    }
    const step = parseInt(stepStr, 10);
    if (step === 0) {
      throw new Error(
        `Field "${fieldName}": step value cannot be zero in "${token}"`
      );
    }
    const result: number[] = [];
    for (let i = min; i <= max; i += step) {
      result.push(i);
    }
    return result;
  }

  // Comma-separated list: must contain only bare integers (no nested ranges/steps)
  if (token.includes(",")) {
    const parts = token.split(",");
    if (parts.some((p) => p === "")) {
      throw new Error(
        `Field "${fieldName}": empty element in list "${token}"`
      );
    }
    const seen = new Set<number>();
    const values: number[] = [];
    for (const part of parts) {
      if (!isNonNegativeInteger(part)) {
        throw new Error(
          `Field "${fieldName}": invalid list item "${part}" in "${token}" — only integers are supported in comma lists`
        );
      }
      const val = parseInt(part, 10);
      if (val < min || val > max) {
        throw new Error(
          `Field "${fieldName}": value ${val} in "${token}" is out of range [${min}, ${max}]`
        );
      }
      if (!seen.has(val)) {
        seen.add(val);
        values.push(val);
      }
    }
    return values.sort((a, b) => a - b);
  }

  // Range: a-b
  if (token.includes("-")) {
    const dashIndex = token.indexOf("-");
    const startStr = token.slice(0, dashIndex);
    const endStr = token.slice(dashIndex + 1);
    if (!isNonNegativeInteger(startStr) || !isNonNegativeInteger(endStr)) {
      throw new Error(
        `Field "${fieldName}": both bounds in range "${token}" must be non-negative integers`
      );
    }
    if (endStr.includes("-")) {
      throw new Error(
        `Field "${fieldName}": malformed range "${token}" — only a single dash is allowed`
      );
    }
    const start = parseInt(startStr, 10);
    const end = parseInt(endStr, 10);
    if (start > end) {
      throw new Error(
        `Field "${fieldName}": range start (${start}) must be <= end (${end}) in "${token}"`
      );
    }
    if (start < min || end > max) {
      throw new Error(
        `Field "${fieldName}": range "${token}" exceeds valid bounds [${min}, ${max}]`
      );
    }
    return buildRange(start, end);
  }

  // Single integer
  if (!isNonNegativeInteger(token)) {
    throw new Error(
      `Field "${fieldName}": unrecognized token "${token}" — expected a number, *, */n, a-b, or a,b,...`
    );
  }
  const val = parseInt(token, 10);
  if (val < min || val > max) {
    throw new Error(
      `Field "${fieldName}": value ${val} is out of range [${min}, ${max}]`
    );
  }
  return [val];
}

export default function parseCron(expression: string): CronExpression {
  if (typeof expression !== "string") {
    throw new TypeError(
      `parseCron: expected a string argument, got ${typeof expression}`
    );
  }

  const trimmed = expression.trim();
  if (trimmed.length === 0) {
    throw new Error("parseCron: expression must not be empty or blank");
  }

  const tokens = trimmed.split(/\s+/);
  if (tokens.length !== 5) {
    throw new Error(
      `parseCron: expected exactly 5 fields (minute hour dayOfMonth month dayOfWeek), got ${tokens.length} in "${expression}"`
    );
  }

  const result = {} as CronExpression;

  for (let i = 0; i < FIELD_ORDER.length; i++) {
    const field = FIELD_ORDER[i];
    const config = FIELD_CONFIGS[field];
    const parsed = parseToken(tokens[i], config, field);

    if (parsed.length === 0) {
      // Defensive guard: a valid token should always produce at least one value
      throw new Error(
        `Field "${field}": token "${tokens[i]}" resolved to an empty value set — this is likely a bug`
      );
    }

    result[field] = parsed;
  }

  return result;
}

type PlainObject = { [key: string]: unknown };
type FlatObject = { [key: string]: unknown };

function isPlainObject(value: unknown): value is PlainObject {
  if (value === null || typeof value !== "object") return false;
  if (Array.isArray(value)) return false;
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function flattenObjectInner(
  obj: PlainObject,
  prefix: string,
  result: FlatObject,
  visited: WeakSet<object>
): void {
  const keys = Object.keys(obj);

  if (keys.length === 0) {
    // Preserve empty plain objects as leaf values rather than dropping them
    if (prefix !== "") {
      result[prefix] = obj;
    }
    return;
  }

  for (const key of keys) {
    if (key === "") {
      // Empty string keys would silently corrupt dot-notation paths; skip them
      continue;
    }

    const fullKey = prefix === "" ? key : `${prefix}.${key}`;
    const value = obj[key];

    if (isPlainObject(value)) {
      if (visited.has(value as object)) {
        // Circular reference — surface as a sentinel rather than infinite-looping
        result[fullKey] = "[Circular]";
      } else {
        visited.add(value as object);
        flattenObjectInner(value as PlainObject, fullKey, result, visited);
      }
    } else {
      // Primitives, arrays, Dates, RegExps, Functions, null, undefined — all leaf values
      result[fullKey] = value;
    }
  }
}

function flattenObject(input: unknown): FlatObject {
  if (!isPlainObject(input)) {
    // Non-plain-object at the top level has no keys to flatten into
    return {};
  }

  const result: FlatObject = {};
  const visited = new WeakSet<object>();
  visited.add(input);
  flattenObjectInner(input, "", result, visited);
  return result;
}

export default flattenObject;

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: Primitive | NestedObject | unknown[] };
type FlatObject = { [key: string]: Primitive };

function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: FlatObject = {}
): FlatObject {
  if (obj === null || typeof obj !== "object") {
    if (prefix) result[prefix] = obj as Primitive;
    return result;
  }

  if (Array.isArray(obj)) {
    if (prefix) result[prefix] = JSON.stringify(obj);
    return result;
  }

  const keys = Object.keys(obj);

  if (keys.length === 0) {
    if (prefix) result[prefix] = {};
    return result;
  }

  for (const key of keys) {
    const value = obj[key];
    const newKey = prefix ? `${prefix}.${key}` : key;

    if (
      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value)
    ) {
      flattenObject(value as NestedObject, newKey, result);
    } else if (Array.isArray(value)) {
      result[newKey] = JSON.stringify(value);
    } else {
      result[newKey] = value as Primitive;
    }
  }

  return result;
}

export default flattenObject;

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: NestedObject | Primitive | Array<unknown> };
type FlatObject = { [key: string]: Primitive | Array<unknown> };

function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: FlatObject = {}
): FlatObject {
  if (obj === null || obj === undefined || typeof obj !== "object" || Array.isArray(obj)) {
    if (prefix) result[prefix] = obj as Primitive | Array<unknown>;
    return result;
  }

  const keys = Object.keys(obj);

  if (keys.length === 0) {
    if (prefix) result[prefix] = {} as unknown as Primitive;
    return result;
  }

  for (const key of keys) {
    const newKey = prefix ? `${prefix}.${key}` : key;
    const value = obj[key];

    if (
      value !== null &&
      value !== undefined &&
      typeof value === "object" &&
      !Array.isArray(value)
    ) {
      flattenObject(value as NestedObject, newKey, result);
    } else {
      result[newKey] = value as Primitive | Array<unknown>;
    }
  }

  return result;
}

export default flattenObject;

export interface CronExpression {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldSpec {
  readonly name: keyof CronExpression;
  readonly min: number;
  readonly max: number;
}

const FIELD_SPECS: readonly FieldSpec[] = [
  { name: "minute", min: 0, max: 59 },
  { name: "hour", min: 0, max: 23 },
  { name: "dayOfMonth", min: 1, max: 31 },
  { name: "month", min: 1, max: 12 },
  { name: "dayOfWeek", min: 0, max: 6 },
];

function assertBoundedInt(
  raw: string,
  spec: FieldSpec,
  context: string
): number {
  const n = Number(raw);
  if (!Number.isInteger(n)) {
    throw new RangeError(
      `Non-integer value "${raw}" in ${spec.name} (context: "${context}")`
    );
  }
  if (n < spec.min || n > spec.max) {
    throw new RangeError(
      `Value ${n} out of range [${spec.min}-${spec.max}] in ${spec.name} (context: "${context}")`
    );
  }
  return n;
}

function buildSequence(start: number, end: number, step: number): number[] {
  if (step <= 0) {
    throw new RangeError(`Step must be a positive integer, got ${step}`);
  }
  if (start > end) {
    throw new RangeError(
      `Range start ${start} must not exceed end ${end}`
    );
  }
  const result: number[] = [];
  for (let i = start; i <= end; i += step) {
    result.push(i);
  }
  return result;
}

function parseAtom(token: string, spec: FieldSpec): number[] {
  const slashIdx = token.indexOf("/");

  if (slashIdx !== -1) {
    const rangePart = token.slice(0, slashIdx);
    const stepPart = token.slice(slashIdx + 1);

    if (stepPart.includes("/")) {
      throw new SyntaxError(
        `Multiple "/" in token "${token}" for ${spec.name}`
      );
    }

    const step = Number(stepPart);
    if (!Number.isInteger(step) || step <= 0) {
      throw new RangeError(
        `Invalid step "${stepPart}" in "${token}" for ${spec.name}`
      );
    }

    if (rangePart === "*") {
      return buildSequence(spec.min, spec.max, step);
    }

    const dashIdx = rangePart.indexOf("-");
    if (dashIdx !== -1) {
      const start = assertBoundedInt(rangePart.slice(0, dashIdx), spec, token);
      const end = assertBoundedInt(rangePart.slice(dashIdx + 1), spec, token);
      return buildSequence(start, end, step);
    }

    const start = assertBoundedInt(rangePart, spec, token);
    return buildSequence(start, spec.max, step);
  }

  if (token === "*") {
    return buildSequence(spec.min, spec.max, 1);
  }

  const dashIdx = token.indexOf("-");
  if (dashIdx !== -1) {
    if (token.indexOf("-", dashIdx + 1) !== -1) {
      throw new SyntaxError(
        `Multiple "-" in token "${token}" for ${spec.name}`
      );
    }
    const start = assertBoundedInt(token.slice(0, dashIdx), spec, token);
    const end = assertBoundedInt(token.slice(dashIdx + 1), spec, token);
    return buildSequence(start, end, 1);
  }

  return [assertBoundedInt(token, spec, token)];
}

function parseField(field: string, spec: FieldSpec): number[] {
  if (field.length === 0) {
    throw new SyntaxError(`Empty field for ${spec.name}`);
  }

  const parts = field.split(",");

  if (parts.some((p) => p.trim().length === 0)) {
    throw new SyntaxError(
      `Empty segment in comma list "${field}" for ${spec.name}`
    );
  }

  const seen = new Set<number>();
  for (const part of parts) {
    for (const v of parseAtom(part.trim(), spec)) {
      seen.add(v);
    }
  }

  return Array.from(seen).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronExpression {
  if (typeof expression !== "string") {
    throw new TypeError(`Expression must be a string`);
  }

  const fields = expression.trim().split(/\s+/);

  if (fields.length !== 5) {
    throw new SyntaxError(
      `Expected 5 fields, got ${fields.length} in "${expression}"`
    );
  }

  const result = {} as CronExpression;

  for (let i = 0; i < FIELD_SPECS.length; i++) {
    const spec = FIELD_SPECS[i];
    result[spec.name] = parseField(fields[i], spec);
  }

  return result;
}

export interface ParsedCron {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldDefinition {
  name: keyof ParsedCron;
  min: number;
  max: number;
}

const FIELD_DEFINITIONS: readonly FieldDefinition[] = [
  { name: "minute", min: 0, max: 59 },
  { name: "hour", min: 0, max: 23 },
  { name: "dayOfMonth", min: 1, max: 31 },
  { name: "month", min: 1, max: 12 },
  { name: "dayOfWeek", min: 0, max: 6 },
];

function buildRange(min: number, max: number): number[] {
  if (min > max) {
    throw new RangeError(`Range start ${min} exceeds range end ${max}.`);
  }
  const result: number[] = [];
  for (let i = min; i <= max; i++) {
    result.push(i);
  }
  return result;
}

function assertWithinBounds(value: number, min: number, max: number, context: string): void {
  if (!Number.isInteger(value) || value < min || value > max) {
    throw new RangeError(
      `Value ${value} in field "${context}" is outside valid range [${min}, ${max}].`
    );
  }
}

function parseSegment(segment: string, min: number, max: number, fieldName: string): number[] {
  // Step: */N or start-end/N
  if (segment.includes("/")) {
    const slashIndex = segment.indexOf("/");
    const stepStr = segment.slice(slashIndex + 1);
    const step = Number(stepStr);

    if (!Number.isInteger(step) || step < 1) {
      throw new RangeError(
        `Step value "${stepStr}" in field "${fieldName}" must be a positive integer.`
      );
    }

    const baseStr = segment.slice(0, slashIndex);
    let rangeMin = min;
    let rangeMax = max;

    if (baseStr !== "*") {
      if (baseStr.includes("-")) {
        const [startStr, endStr] = baseStr.split("-");
        rangeMin = Number(startStr);
        rangeMax = Number(endStr);
        if (!Number.isInteger(rangeMin) || !Number.isInteger(rangeMax)) {
          throw new TypeError(
            `Non-integer values in range "${baseStr}" in field "${fieldName}".`
          );
        }
        assertWithinBounds(rangeMin, min, max, fieldName);
        assertWithinBounds(rangeMax, min, max, fieldName);
      } else {
        rangeMin = Number(baseStr);
        if (!Number.isInteger(rangeMin)) {
          throw new TypeError(
            `Non-integer step base "${baseStr}" in field "${fieldName}".`
          );
        }
        assertWithinBounds(rangeMin, min, max, fieldName);
        rangeMax = max;
      }
    }

    if (rangeMin > rangeMax) {
      throw new RangeError(
        `Range start ${rangeMin} exceeds range end ${rangeMax} in field "${fieldName}".`
      );
    }

    const result: number[] = [];
    for (let i = rangeMin; i <= rangeMax; i += step) {
      result.push(i);
    }
    return result;
  }

  // Wildcard
  if (segment === "*") {
    return buildRange(min, max);
  }

  // Range: N-M
  if (segment.includes("-")) {
    const parts = segment.split("-");
    if (parts.length !== 2) {
      throw new SyntaxError(
        `Invalid range expression "${segment}" in field "${fieldName}".`
      );
    }
    const rangeMin = Number(parts[0]);
    const rangeMax = Number(parts[1]);
    if (!Number.isInteger(rangeMin) || !Number.isInteger(rangeMax)) {
      throw new TypeError(
        `Non-integer values in range "${segment}" in field "${fieldName}".`
      );
    }
    assertWithinBounds(rangeMin, min, max, fieldName);
    assertWithinBounds(rangeMax, min, max, fieldName);
    return buildRange(rangeMin, rangeMax);
  }

  // Plain number
  const value = Number(segment);
  if (!Number.isInteger(value) || isNaN(value)) {
    throw new TypeError(
      `Non-integer value "${segment}" in field "${fieldName}".`
    );
  }
  assertWithinBounds(value, min, max, fieldName);
  return [value];
}

function parseField(token: string, min: number, max: number, fieldName: string): number[] {
  if (token === undefined || token === null || token.trim() === "") {
    throw new SyntaxError(`Missing or empty token for field "${fieldName}".`);
  }

  const trimmed = token.trim();

  // Comma-separated list: each segment parsed individually, results merged and deduplicated
  const segments = trimmed.split(",");
  const seen = new Set<number>();
  const result: number[] = [];

  for (const segment of segments) {
    const segTrimmed = segment.trim();
    if (segTrimmed === "") {
      throw new SyntaxError(
        `Empty segment in comma-separated list for field "${fieldName}".`
      );
    }
    const values = parseSegment(segTrimmed, min, max, fieldName);
    for (const v of values) {
      if (!seen.has(v)) {
        seen.add(v);
        result.push(v);
      }
    }
  }

  result.sort((a, b) => a - b);
  return result;
}

export default function parseCron(expression: string): ParsedCron {
  if (typeof expression !== "string") {
    throw new TypeError(`Cron expression must be a string; received ${typeof expression}.`);
  }

  const tokens = expression.trim().split(/\s+/);

  if (tokens.length !== 5) {
    throw new SyntaxError(
      `Cron expression must have exactly 5 fields; received ${tokens.length}: "${expression}".`
    );
  }

  const result = {} as ParsedCron;

  for (let i = 0; i < FIELD_DEFINITIONS.length; i++) {
    const { name, min, max } = FIELD_DEFINITIONS[i];
    result[name] = parseField(tokens[i], min, max, name);
  }

  return result;
}

type CronResult = {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
};

type FieldConfig = {
  min: number;
  max: number;
};

const FIELD_CONFIGS: FieldConfig[] = [
  { min: 0, max: 59 },  // minute
  { min: 0, max: 23 },  // hour
  { min: 1, max: 31 },  // dayOfMonth
  { min: 1, max: 12 },  // month
  { min: 0, max: 6 },   // dayOfWeek
];

const FIELD_NAMES = ["minute", "hour", "dayOfMonth", "month", "dayOfWeek"] as const;

function parseInteger(value: string): number {
  const n = parseInt(value, 10);
  if (isNaN(n) || String(n) !== value.trim()) {
    throw new Error(`Invalid integer: "${value}"`);
  }
  return n;
}

function assertInRange(value: number, min: number, max: number, context: string): void {
  if (value < min || value > max) {
    throw new Error(`Value ${value} out of range [${min}, ${max}] in "${context}"`);
  }
}

function expandRange(start: number, end: number, step: number, min: number, max: number): number[] {
  if (start > end) {
    throw new Error(`Invalid range: start ${start} > end ${end}`);
  }
  if (step < 1) {
    throw new Error(`Step must be >= 1, got ${step}`);
  }
  const values: number[] = [];
  for (let i = start; i <= end; i += step) {
    assertInRange(i, min, max, `range ${start}-${end}/${step}`);
    values.push(i);
  }
  return values;
}

function parseSegment(segment: string, config: FieldConfig): number[] {
  const { min, max } = config;

  // Step with wildcard: */n
  if (segment.startsWith("*/")) {
    const stepStr = segment.slice(2);
    const step = parseInteger(stepStr);
    if (step < 1) {
      throw new Error(`Step must be >= 1, got ${step}`);
    }
    return expandRange(min, max, step, min, max);
  }

  // Wildcard: *
  if (segment === "*") {
    return expandRange(min, max, 1, min, max);
  }

  // Range with optional step: a-b or a-b/n
  if (segment.includes("-")) {
    const slashIndex = segment.indexOf("/");
    const rangeStr = slashIndex !== -1 ? segment.slice(0, slashIndex) : segment;
    const stepStr = slashIndex !== -1 ? segment.slice(slashIndex + 1) : "1";

    const dashIndex = rangeStr.indexOf("-");
    const startStr = rangeStr.slice(0, dashIndex);
    const endStr = rangeStr.slice(dashIndex + 1);

    const start = parseInteger(startStr);
    const end = parseInteger(endStr);
    const step = parseInteger(stepStr);

    assertInRange(start, min, max, segment);
    assertInRange(end, min, max, segment);

    return expandRange(start, end, step, min, max);
  }

  // Step without wildcard: n/step (start from n, step through max)
  if (segment.includes("/")) {
    const [startStr, stepStr] = segment.split("/");
    const start = parseInteger(startStr);
    const step = parseInteger(stepStr);
    assertInRange(start, min, max, segment);
    return expandRange(start, max, step, min, max);
  }

  // Plain number
  const value = parseInteger(segment);
  assertInRange(value, min, max, segment);
  return [value];
}

function parseField(field: string, config: FieldConfig): number[] {
  const segments = field.split(",");
  if (segments.length === 0) {
    throw new Error(`Empty field`);
  }

  const valueSet = new Set<number>();

  for (const segment of segments) {
    const trimmed = segment.trim();
    if (trimmed === "") {
      throw new Error(`Empty segment in field "${field}"`);
    }
    const values = parseSegment(trimmed, config);
    for (const v of values) {
      valueSet.add(v);
    }
  }

  return Array.from(valueSet).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronResult {
  if (typeof expression !== "string") {
    throw new Error(`Expected a string, got ${typeof expression}`);
  }

  const fields = expression.trim().split(/\s+/);

  if (fields.length !== 5) {
    throw new Error(
      `Expected 5 fields, got ${fields.length}: "${expression}"`
    );
  }

  const result = {} as CronResult;

  for (let i = 0; i < 5; i++) {
    const name = FIELD_NAMES[i];
    const config = FIELD_CONFIGS[i];
    result[name] = parseField(fields[i], config);
  }

  return result;
}

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: Primitive | NestedObject | Array<unknown> };
type FlatObject = { [key: string]: Primitive | Array<unknown> };

function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: FlatObject = {}
): FlatObject {
  if (obj === null || obj === undefined || typeof obj !== "object") {
    if (prefix) result[prefix] = obj as Primitive;
    return result;
  }

  if (Array.isArray(obj)) {
    if (prefix) result[prefix] = obj;
    return result;
  }

  const keys = Object.keys(obj);

  if (keys.length === 0) {
    if (prefix) result[prefix] = {};
    return result;
  }

  for (const key of keys) {
    const value = obj[key];
    const newKey = prefix ? `${prefix}.${key}` : key;

    if (
      value !== null &&
      value !== undefined &&
      typeof value === "object" &&
      !Array.isArray(value)
    ) {
      flattenObject(value as NestedObject, newKey, result);
    } else {
      result[newKey] = value as Primitive | Array<unknown>;
    }
  }

  return result;
}

export default flattenObject;

type CronField = "minute" | "hour" | "dayOfMonth" | "month" | "dayOfWeek";

interface CronResult {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<CronField, { min: number; max: number }> = {
  minute: { min: 0, max: 59 },
  hour: { min: 0, max: 23 },
  dayOfMonth: { min: 1, max: 31 },
  month: { min: 1, max: 12 },
  dayOfWeek: { min: 0, max: 7 },
};

function generateRange(min: number, max: number, step = 1): number[] {
  const result: number[] = [];
  for (let i = min; i <= max; i += step) {
    result.push(i);
  }
  return result;
}

function dedupeSort(values: number[]): number[] {
  return [...new Set(values)].sort((a, b) => a - b);
}

function parseSegment(segment: string, field: CronField): number[] {
  const { min, max } = FIELD_RANGES[field];

  // Wildcard: *
  if (segment === "*") {
    return generateRange(min, max);
  }

  // Step with wildcard: */N
  const stepWildcardMatch = segment.match(/^\*\/(\d+)$/);
  if (stepWildcardMatch) {
    const step = parseInt(stepWildcardMatch[1], 10);
    if (step < 1) throw new Error(`Invalid step value in field "${field}": ${segment}`);
    return generateRange(min, max, step);
  }

  // Range with optional step: N-M or N-M/S
  const rangeMatch = segment.match(/^(\d+)-(\d+)(?:\/(\d+))?$/);
  if (rangeMatch) {
    const rangeMin = parseInt(rangeMatch[1], 10);
    const rangeMax = parseInt(rangeMatch[2], 10);
    const step = rangeMatch[3] !== undefined ? parseInt(rangeMatch[3], 10) : 1;

    if (rangeMin < min || rangeMax > max) {
      throw new Error(`Range out of bounds in field "${field}": ${segment} (valid: ${min}-${max})`);
    }
    if (rangeMin > rangeMax) {
      throw new Error(`Invalid range in field "${field}": ${segment} (start > end)`);
    }
    if (step < 1) {
      throw new Error(`Invalid step value in field "${field}": ${segment}`);
    }
    return generateRange(rangeMin, rangeMax, step);
  }

  // Single number
  const numMatch = segment.match(/^(\d+)$/);
  if (numMatch) {
    const value = parseInt(numMatch[1], 10);
    if (value < min || value > max) {
      throw new Error(`Value out of bounds in field "${field}": ${value} (valid: ${min}-${max})`);
    }
    // Normalize dayOfWeek: treat 7 as 0 (both are Sunday)
    if (field === "dayOfWeek" && value === 7) return [0];
    return [value];
  }

  throw new Error(`Unsupported cron segment in field "${field}": ${segment}`);
}

function parseField(expression: string, field: CronField): number[] {
  const parts = expression.split(",");
  const values: number[] = [];

  for (const part of parts) {
    const trimmed = part.trim();
    if (!trimmed) throw new Error(`Empty segment in field "${field}"`);
    values.push(...parseSegment(trimmed, field));
  }

  return dedupeSort(values);
}

export default function parseCron(expression: string): CronResult {
  if (typeof expression !== "string" || !expression.trim()) {
    throw new Error("Cron expression must be a non-empty string");
  }

  const fields = expression.trim().split(/\s+/);

  if (fields.length !== 5) {
    throw new Error(
      `Invalid cron expression: expected 5 fields, got ${fields.length}`
    );
  }

  const [minuteExpr, hourExpr, dayOfMonthExpr, monthExpr, dayOfWeekExpr] = fields;

  return {
    minute: parseField(minuteExpr, "minute"),
    hour: parseField(hourExpr, "hour"),
    dayOfMonth: parseField(dayOfMonthExpr, "dayOfMonth"),
    month: parseField(monthExpr, "month"),
    dayOfWeek: parseField(dayOfWeekExpr, "dayOfWeek"),
  };
}

export interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldBounds {
  min: number;
  max: number;
}

const FIELD_BOUNDS: Record<keyof CronFields, FieldBounds> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 6  },
};

const FIELD_ORDER: ReadonlyArray<keyof CronFields> = [
  "minute",
  "hour",
  "dayOfMonth",
  "month",
  "dayOfWeek",
];

function generateRange(start: number, end: number, step: number): number[] {
  if (step <= 0) {
    throw new RangeError(`Step value must be a positive integer, received: ${step}`);
  }
  const result: number[] = [];
  for (let i = start; i <= end; i += step) {
    result.push(i);
  }
  return result;
}

function assertInBounds(value: number, bounds: FieldBounds, context: string): void {
  if (!Number.isInteger(value) || value < bounds.min || value > bounds.max) {
    throw new RangeError(
      `Value ${value} is outside valid range [${bounds.min}, ${bounds.max}] in segment: "${context}"`
    );
  }
}

function assertRangeOrder(start: number, end: number, context: string): void {
  if (start > end) {
    throw new RangeError(
      `Range start (${start}) must not exceed range end (${end}) in segment: "${context}"`
    );
  }
}

function parseSegment(segment: string, bounds: FieldBounds): number[] {
  if (segment.length === 0) {
    throw new SyntaxError(`Empty segment encountered`);
  }

  // */step
  let m = segment.match(/^\*\/(\d+)$/);
  if (m !== null) {
    const step = parseInt(m[1], 10);
    if (step <= 0) {
      throw new RangeError(`Step must be a positive integer in segment: "${segment}"`);
    }
    return generateRange(bounds.min, bounds.max, step);
  }

  // start-end/step
  m = segment.match(/^(\d+)-(\d+)\/(\d+)$/);
  if (m !== null) {
    const start = parseInt(m[1], 10);
    const end   = parseInt(m[2], 10);
    const step  = parseInt(m[3], 10);
    assertInBounds(start, bounds, segment);
    assertInBounds(end,   bounds, segment);
    assertRangeOrder(start, end, segment);
    if (step <= 0) {
      throw new RangeError(`Step must be a positive integer in segment: "${segment}"`);
    }
    return generateRange(start, end, step);
  }

  // number/step (start at number, step through max)
  m = segment.match(/^(\d+)\/(\d+)$/);
  if (m !== null) {
    const start = parseInt(m[1], 10);
    const step  = parseInt(m[2], 10);
    assertInBounds(start, bounds, segment);
    if (step <= 0) {
      throw new RangeError(`Step must be a positive integer in segment: "${segment}"`);
    }
    return generateRange(start, bounds.max, step);
  }

  // start-end
  m = segment.match(/^(\d+)-(\d+)$/);
  if (m !== null) {
    const start = parseInt(m[1], 10);
    const end   = parseInt(m[2], 10);
    assertInBounds(start, bounds, segment);
    assertInBounds(end,   bounds, segment);
    assertRangeOrder(start, end, segment);
    return generateRange(start, end, 1);
  }

  // wildcard
  if (segment === "*") {
    return generateRange(bounds.min, bounds.max, 1);
  }

  // single integer
  m = segment.match(/^(\d+)$/);
  if (m !== null) {
    const value = parseInt(m[1], 10);
    assertInBounds(value, bounds, segment);
    return [value];
  }

  throw new SyntaxError(`Unrecognized cron segment syntax: "${segment}"`);
}

function parseField(expression: string, bounds: FieldBounds): number[] {
  if (expression.length === 0) {
    throw new SyntaxError(`Empty field expression`);
  }

  const segments = expression.split(",");

  if (segments.some((s) => s.trim().length === 0)) {
    throw new SyntaxError(`Empty segment in comma-separated list: "${expression}"`);
  }

  const valueSet = new Set<number>();

  for (const segment of segments) {
    const parsed = parseSegment(segment.trim(), bounds);
    for (const v of parsed) {
      valueSet.add(v);
    }
  }

  return Array.from(valueSet).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronFields {
  if (typeof expression !== "string") {
    throw new TypeError(`Expression must be a string, received: ${typeof expression}`);
  }

  const trimmed = expression.trim();

  if (trimmed.length === 0) {
    throw new SyntaxError(`Cron expression must not be empty`);
  }

  const fields = trimmed.split(/\s+/);

  if (fields.length !== 5) {
    throw new SyntaxError(
      `Cron expression must have exactly 5 fields, found ${fields.length}: "${trimmed}"`
    );
  }

  const result = {} as CronFields;

  for (let i = 0; i < FIELD_ORDER.length; i++) {
    const fieldName = FIELD_ORDER[i];
    const bounds    = FIELD_BOUNDS[fieldName];
    result[fieldName] = parseField(fields[i], bounds);
  }

  return result;
}

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: Primitive | NestedObject | Array<unknown> };
type FlatObject = { [key: string]: Primitive };

function flattenObject(
  obj: NestedObject,
  prefix: string = "",
  result: FlatObject = {}
): FlatObject {
  if (obj === null || obj === undefined || typeof obj !== "object" || Array.isArray(obj)) {
    if (prefix) result[prefix] = obj as Primitive;
    return result;
  }

  const keys = Object.keys(obj);

  if (keys.length === 0) {
    if (prefix) result[prefix] = {} as unknown as Primitive;
    return result;
  }

  for (const key of keys) {
    const value = obj[key];
    const newKey = prefix ? `${prefix}.${key}` : key;

    if (
      value !== null &&
      value !== undefined &&
      typeof value === "object" &&
      !Array.isArray(value)
    ) {
      flattenObject(value as NestedObject, newKey, result);
    } else {
      result[newKey] = Array.isArray(value) ? (value as unknown as Primitive) : (value as Primitive);
    }
  }

  return result;
}

export default flattenObject;

type Primitive = string | number | boolean | null | undefined | symbol | bigint;
type FlatValue = Primitive | Date | RegExp | Function | Array<unknown>;
type NestedObject = { [key: string]: unknown };
type FlatObject = { [key: string]: FlatValue };

function isPlainObject(value: unknown): value is NestedObject {
  if (value === null || typeof value !== "object") {
    return false;
  }
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function flattenObject(
  input: unknown,
  prefix: string = "",
  visited: WeakSet<object> = new WeakSet()
): FlatObject {
  if (!isPlainObject(input)) {
    return prefix !== "" ? { [prefix]: input as FlatValue } : {};
  }

  if (visited.has(input)) {
    return prefix !== "" ? { [prefix]: "[Circular]" } : {};
  }

  visited.add(input);

  const entries = Object.entries(input);

  if (entries.length === 0) {
    return prefix !== "" ? { [prefix]: {} as unknown as FlatValue } : {};
  }

  const result: FlatObject = {};

  for (const [key, value] of entries) {
    const fullKey = prefix !== "" ? `${prefix}.${key}` : key;

    if (isPlainObject(value) && !visited.has(value)) {
      const nested = flattenObject(value, fullKey, visited);
      for (const [nestedKey, nestedValue] of Object.entries(nested)) {
        result[nestedKey] = nestedValue;
      }
    } else {
      result[fullKey] = value as FlatValue;
    }
  }

  visited.delete(input);

  return result;
}

export default flattenObject;

type CronResult = {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
};

type FieldConfig = {
  min: number;
  max: number;
};

const FIELD_CONFIGS: FieldConfig[] = [
  { min: 0, max: 59 },  // minute
  { min: 0, max: 23 },  // hour
  { min: 1, max: 31 },  // dayOfMonth
  { min: 1, max: 12 },  // month
  { min: 0, max: 7 },   // dayOfWeek (0 and 7 both = Sunday)
];

const FIELD_NAMES = ["minute", "hour", "dayOfMonth", "month", "dayOfWeek"] as const;

function parseInteger(value: string): number {
  const num = parseInt(value, 10);
  if (isNaN(num) || String(num) !== value.trim()) {
    throw new Error(`Invalid integer: "${value}"`);
  }
  return num;
}

function assertInRange(value: number, min: number, max: number, context: string): void {
  if (value < min || value > max) {
    throw new Error(`Value ${value} out of range [${min}, ${max}] in ${context}`);
  }
}

function expandRange(start: number, end: number, min: number, max: number, context: string): number[] {
  assertInRange(start, min, max, context);
  assertInRange(end, min, max, context);
  if (start > end) {
    throw new Error(`Invalid range ${start}-${end} in ${context}: start must be <= end`);
  }
  const result: number[] = [];
  for (let i = start; i <= end; i++) {
    result.push(i);
  }
  return result;
}

function expandStep(rangeExpr: string, step: number, config: FieldConfig, context: string): number[] {
  if (step <= 0) {
    throw new Error(`Step must be positive in ${context}`);
  }

  let start: number;
  let end: number;

  if (rangeExpr === "*") {
    start = config.min;
    end = config.max;
  } else if (rangeExpr.includes("-")) {
    const parts = rangeExpr.split("-");
    if (parts.length !== 2) {
      throw new Error(`Invalid range expression "${rangeExpr}" in ${context}`);
    }
    start = parseInteger(parts[0]);
    end = parseInteger(parts[1]);
    assertInRange(start, config.min, config.max, context);
    assertInRange(end, config.min, config.max, context);
    if (start > end) {
      throw new Error(`Invalid range ${start}-${end} in ${context}`);
    }
  } else {
    start = parseInteger(rangeExpr);
    assertInRange(start, config.min, config.max, context);
    end = config.max;
  }

  const result: number[] = [];
  for (let i = start; i <= end; i += step) {
    result.push(i);
  }
  return result;
}

function parseField(expr: string, config: FieldConfig, fieldName: string): number[] {
  const context = `field "${fieldName}"`;

  if (expr.includes(",")) {
    const parts = expr.split(",");
    const values = new Set<number>();
    for (const part of parts) {
      const expanded = parseField(part.trim(), config, fieldName);
      for (const v of expanded) {
        values.add(v);
      }
    }
    return Array.from(values).sort((a, b) => a - b);
  }

  if (expr.includes("/")) {
    const slashParts = expr.split("/");
    if (slashParts.length !== 2) {
      throw new Error(`Invalid step expression "${expr}" in ${context}`);
    }
    const step = parseInteger(slashParts[1]);
    return expandStep(slashParts[0], step, config, context);
  }

  if (expr === "*") {
    return expandRange(config.min, config.max, config.min, config.max, context);
  }

  if (expr.includes("-")) {
    const rangeParts = expr.split("-");
    if (rangeParts.length !== 2) {
      throw new Error(`Invalid range expression "${expr}" in ${context}`);
    }
    const start = parseInteger(rangeParts[0]);
    const end = parseInteger(rangeParts[1]);
    return expandRange(start, end, config.min, config.max, context);
  }

  const value = parseInteger(expr);
  assertInRange(value, config.min, config.max, context);
  return [value];
}

function normalizeDayOfWeek(values: number[]): number[] {
  const normalized = new Set<number>();
  for (const v of values) {
    normalized.add(v === 7 ? 0 : v);
  }
  return Array.from(normalized).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronResult {
  if (typeof expression !== "string") {
    throw new Error("Cron expression must be a string");
  }

  const fields = expression.trim().split(/\s+/);

  if (fields.length !== 5) {
    throw new Error(
      `Cron expression must have exactly 5 fields, got ${fields.length}: "${expression}"`
    );
  }

  const parsedFields = fields.map((field, index) =>
    parseField(field, FIELD_CONFIGS[index], FIELD_NAMES[index])
  );

  const [minute, hour, dayOfMonth, month, dayOfWeek] = parsedFields;

  return {
    minute,
    hour,
    dayOfMonth,
    month,
    dayOfWeek: normalizeDayOfWeek(dayOfWeek),
  };
}
